// 追加300語（ニュース150 + TOEIC生活150）
const WORDS_EXTRA = [
  { en: "ambassador", pos: "名詞", kana: "アンバサダー", ja: "大使", ex: "The U.S. ambassador to Japan met with senior officials to discuss trade negotiations.", exJa: "日本駐在米国大使は、貿易交渉について上級官僚と会談した。", cat: "ニュース", etym: "ラテン語 ambactus（召し使い）が語源。中世ラテン語で ambasciator となり、「派遣された者」を意味する。embassador とも表記される。", syn: "envoy（特使・臨時の使節）, diplomat（外交官・総称的）, emissary（密使・非公式の使者）" },
  { en: "embassy", pos: "名詞", kana: "エンバシー", ja: "大使館", ex: "The embassy issued a travel advisory warning citizens about potential security risks in the region.", exJa: "その大使館は、同地域での潜在的なセキュリティリスクについて国民に渡航勧告を発令した。", cat: "ニュース", etym: "ambassador と同じく ambactus に由来。ambassador の任務先・外交使節団を指す建物や機関を意味するようになった。", syn: "consulate（領事館・下位の外交機関）, legation（公使館・歴史的呼称）" },
  { en: "envoy", pos: "名詞", kana: "エンボイ", ja: "特使", ex: "The presidential envoy was dispatched to negotiate peace talks between the two nations.", exJa: "大統領特使は両国間の和平交渉を仲介するために派遣された。", cat: "ニュース", etym: "フランス語 envoyé（送られた者）に由来。ラテン語 in + via（道）で「道に出される」→「派遣される」。ambassador より臨時・特定目的の使者のニュアンス。", syn: "ambassador（大使・常設の代表）, emissary（密使・極秘任務向け）, delegate（代表者・会議向け）" },
  { en: "delegate", pos: "名詞", kana: "デリゲイト", ja: "代表者", ex: "Each country sent five delegates to represent their interests at the international conference.", exJa: "各国は国際会議で自国の利益を代表するために5人の代表者を派遣した。", cat: "ニュース", etym: "ラテン語 delegare（託す、委任する）。de（下へ）+ legare（選んで任せる）。delegated authority など「権限委譲」の概念に直結。", syn: "representative（代表・広い文脈で）, envoy（特使・外交的）, deputy（副代理人・格下感）" },
  { en: "delegation", pos: "名詞", kana: "デレゲーション", ja: "代表団", ex: "The Russian delegation walked out of the meeting in protest over the latest sanctions.", exJa: "ロシア代表団は最新の制裁に抗議して会議から退席した。", cat: "ニュース", etym: "delegate と同根。複数の delegate で構成される団体・グループ。-tion は行為や結果を名詞化する接尾辞。", syn: "mission（派遣団・特定目的向け）, contingent（派遣部隊・人数限定感）" },
  { en: "bilateral", pos: "名詞", kana: "バイラテラル", ja: "二国間", ex: "The two countries signed a bilateral trade agreement to strengthen economic ties.", exJa: "両国は経済関係を強化するための二国間貿易協定に署名した。", cat: "ニュース", etym: "ラテン語 bi（二）+ latus（側）。両側・二者間を意味する。lateral（横の）と同根。", syn: "two-sided（二者間・広義）, bilateral（外交的・対称性重視）" },
  { en: "multilateral", pos: "名詞", kana: "マルチラテラル", ja: "多国間", ex: "The UN organized multilateral talks to address climate change with representatives from 195 countries.", exJa: "国連は195カ国の代表者を交えて気候変動に対処するための多国間協議を開催した。", cat: "ニュース", etym: "ラテン語 multi（多くの）+ latus（側）。bilateral の拡張形で、複数国の合意・枠組みを指す。", syn: "many-sided（多者間・広義）, regional（地域的・スケール限定）" },
  { en: "communique", pos: "名詞", kana: "コミュニケ", ja: "公式声明", ex: "After the summit, the leaders issued a joint communique reaffirming their commitment to regional stability.", exJa: "首脳会談後、首脳たちは地域安定への決意を再確認する共同声明を発表した。", cat: "ニュース", etym: "フランス語 communiqué（伝えられたもの）。communicate の過去分詞形に由来。公式声明・プレスリリースの外交用語として確立。", syn: "statement（声明・一般的）, declaration（宣言・正式感強い）, announcement（発表・広く公知向け）" },
  { en: "jurisdiction", pos: "名詞", kana: "ジュリスディクション", ja: "管轄権", ex: "The international court has jurisdiction over war crimes committed in the conflict zone.", exJa: "国際裁判所は紛争地域で犯された戦争犯罪に対する管轄権を有している。", cat: "ニュース", etym: "ラテン語 jurisdictio。jus（法律）+ dictio（宣言）→「法を宣言する権限」。judge・judicial と同根。", syn: "authority（権限・広義）, purview（職務範囲・英国寄り）, domain（領域・範囲感）" },
  { en: "tribunal", pos: "名詞", kana: "トライビューナル", ja: "裁判所", ex: "The war crimes tribunal sentenced the former general to life imprisonment.", exJa: "戦犯法廷は元将軍に終身刑の判決を言い渡した。", cat: "ニュース", etym: "ラテン語 tribunal。tribunus（民衆の守護者）+ -al。古代ローマの高位官職から、司法を行う場・機関を指すようになった。", syn: "court（法廷・一般的）, bench（判事席・法廷環境）, panel（委員会・複数判事感）" },
  { en: "indictment", pos: "名詞", kana: "インダイトメント", ja: "起訴", ex: "The prosecutor filed an indictment against three executives for fraud and embezzlement.", exJa: "検察は詐欺と横領の罪で3人の経営幹部を起訴した。", cat: "ニュース", etym: "ラテン語 in + dictare（述べ立てる）。容疑を正式に「述べ立てる」行為→起訴状。indict（起訴する）の名詞形。", syn: "charge（容疑・起訴前）, accusation（告発・感情的）, prosecution（公訴・検察側の行動）" },
  { en: "arbitration", pos: "名詞", kana: "アービトレーション", ja: "仲裁", ex: "The two companies agreed to submit their dispute to international arbitration rather than pursue litigation.", exJa: "両社は訴訟ではなく国際仲裁に紛争を付託することに合意した。", cat: "ニュース", etym: "ラテン語 arbitrari（判断する、決定する）。arbitrator（仲裁者）の名詞形。訴訟よりも民間の紛争解決手段として位置づけられる。", syn: "mediation（調停・中立者の仲介）, conciliation（和解・友好的解決）, negotiation（交渉・当事者主体）" },
  { en: "watchdog", pos: "名詞", kana: "ウォッチドッグ", ja: "監視機関", ex: "An independent watchdog group revealed that the company had violated environmental regulations for years.", exJa: "独立した監視機関が、その企業が何年にもわたって環境規制に違反していたことを明らかにした。", cat: "ニュース", etym: "コアイメージ: watch（監視する）+ dog（番犬）。番犬が危険を吠えて知らせるように、不正を監視・告発する独立機関・メディアを指す。", syn: "regulator（規制当局・公式権限）, inspector（査察官・個人）, overseer（監督者・人事）" },
  { en: "whistleblower", pos: "名詞", kana: "ホイッスルブロワー", ja: "内部告発者", ex: "The whistleblower exposed classified surveillance programs that had been operating without congressional approval.", exJa: "内部告発者は議会の承認なく運営されていた機密監視プログラムを暴露した。", cat: "ニュース", etym: "コアイメージ: whistle（笛を吹く）+ blower（吹く人）。警官が笛を吹いて不正を告発する様から、組織内の違法行為を公表する人物を指す。", syn: "informant（情報提供者・刑事向け）, leaker（情報漏らし者・否定的）, dissident（異議唱道者・政治的）" },
  { en: "disinformation", pos: "名詞", kana: "ディスインフォメーション", ja: "偽情報", ex: "Intelligence agencies warned that foreign actors were spreading disinformation to influence the election.", exJa: "情報機関は、外国勢力が選挙に影響を与えるために偽情報を流布していると警告した。", cat: "ニュース", etym: "dis（反対に、否定）+ information。真実と異なる情報を意図的に広めるロシア語 dezinformatsiya が英語化。misinformation（誤情報）より計画性が強い。", syn: "misinformation（誤情報・意図的でない）, propaganda（プロパガンダ・組織的説得）, fake news（フェイクニュース・最近の造語）" },
  { en: "narrative", pos: "名詞", kana: "ナラティブ", ja: "語り口", ex: "The government's narrative about the economic recovery has shifted significantly since the election.", exJa: "政府の経済回復についての語り口は選挙以来、大きく変わった", cat: "ニュース", etym: "ラテン語 narrare（話す）に由来。gnarus（知る）が語根で、「知っていることを順序立てて話す」が原義。narrate・narrator と同根", syn: "story(物語全体), account(事実に基づく説明), framing(解釈の枠組み)" },
  { en: "rhetoric", pos: "名詞", kana: "レトリック", ja: "政治的言辞", ex: "Political analysts say the candidate's fiery rhetoric is designed to energize his base rather than win moderates.", exJa: "政治分析家は、候補者の激しい言辞は中道派を獲得するのではなく、支持層を鼓舞するためだと指摘している", cat: "ニュース", etym: "ギリシャ語 rhetor（弁論家）に由来。古代から政治演説の説得技法を指す学問用語。rhetorical question（反語）などで現代も使用", syn: "discourse(言説・議論), messaging(メッセージ発信), propaganda(宣伝・一方的主張)" },
  { en: "briefing", pos: "名詞", kana: "ブリーフィング", ja: "記者説明", ex: "At Thursday's press briefing, the Pentagon spokesperson declined to comment on specific military operations.", exJa: "木曜日の記者説明会で、国防総省報道官は特定の軍事作戦についてのコメントを避けた", cat: "ニュース", etym: "brief（短い）の動詞形。17世紀から法廷用語で「要点を伝える」の意。press briefing は現代ニュース用語の定番表現", syn: "press conference(記者会見・対話形式), statement(声明・一方的発表), debriefing(報告会・詳細な聞き取り)" },
  { en: "spokesperson", pos: "名詞", kana: "スポークスパーソン", ja: "報道官", ex: "The White House spokesperson issued a statement denying allegations of misconduct.", exJa: "ホワイトハウス報道官は不正行為の疑惑を否定する声明を発表した", cat: "ニュース", etym: "speak（話す）+ person。1950年代に公的機関の「公式な声」として定着した比較的新しい用語。spokesman・spokeswoman の中立的な形", syn: "press secretary(報道担当官・より高位), official(公務員・総称), representative(代表者・広く)" },
  { en: "correspondent", pos: "名詞", kana: "コレスポンデント", ja: "特派員", ex: "Our Tokyo correspondent reports that negotiations between the two countries have reached a critical juncture.", exJa: "東京特派員は、両国の交渉が重大な局面に達したと報告している", cat: "ニュース", etym: "ラテン語 correspond（一致する・応答する）。18世紀から遠方から情報を「通信で送る」人を指す。correspond・correspondence と同根", syn: "reporter(記者・一般的), journalist(ジャーナリスト・職業全般), field reporter(現地記者・より具体的)" },
  { en: "bureau", pos: "名詞", kana: "ビューロー", ja: "支局", ex: "The news agency maintains bureaus in over 50 countries to ensure rapid reporting.", exJa: "その通信社は迅速な報道を確保するため50カ国以上に支局を持っている", cat: "ニュース", etym: "フランス語 bureau（机・事務所）に由来。14世紀のビロード布から机や机の上の布へと意味が移行。bureaucrat と同根", syn: "office(事務所・一般的), branch(支部・広く), station(駅・放送局の中継地)" },
  { en: "separatist", pos: "名詞", kana: "セパラティスト", ja: "分離主義者", ex: "Authorities arrested several separatist leaders accused of planning armed demonstrations.", exJa: "当局は武装デモ計画を指控える分離主義指導者数人を逮捕した", cat: "ニュース", etym: "ラテン語 separare（分ける）+ -ist。16世紀の宗教用語から政治用語へ。separate・separation と同根", syn: "secessionist(脱出主義者・より法的), independence activist(独立活動家・より現地的)" },
  { en: "extremism", pos: "名詞", kana: "エクストリーミズム", ja: "過激主義", ex: "Intelligence agencies are increasingly concerned about the rise of extremism in rural communities.", exJa: "情報機関は農村部における過激主義の台頭についてますます懸念を強めている", cat: "ニュース", etym: "ラテン語 extremus（最も外側・最終的）から。extreme の名詞化。extremist・extremely と同根", syn: "radicalism(根本的主義・意識形態), militancy(戦闘的姿勢・行動重視), fanaticism(狂信・感情重視)" },
  { en: "radicalization", pos: "名詞", kana: "ラディカライゼーション", ja: "過激化", ex: "Experts debate whether online content accelerates the radicalization of vulnerable young people.", exJa: "専門家は、オンラインコンテンツが脆弱な若者の過激化を加速させるかどうかについて議論している", cat: "ニュース", etym: "ラテン語 radix（根）から。18世紀に政治的「根本的変化」の意。radical・radicalize と同根", syn: "militarization(軍事化・武装化), politicization(政治化・政治関与化), polarization(二極化・対立激化)" },
  { en: "flashpoint", pos: "名詞", kana: "フラッシュポイント", ja: "緊張地域", ex: "The disputed border region remains a flashpoint between the two nations.", exJa: "係争中の国境地域は両国間の緊張地域として存在し続けている", cat: "ニュース", etym: "flash（ぱっと光る）+ point。1960年代の冷戦用語で「いつでも対立が爆発する地点」。物理の引火点から政治用語へ", syn: "hotspot(紛争地域・より一般的), trouble spot(問題地域・口語的), conflict zone(紛争地帯・より広い範囲)" },
  { en: "crackdown", pos: "名詞", kana: "クラックダウン", ja: "取り締まり強化", ex: "The government announced a crackdown on unauthorized street protests in major cities.", exJa: "政府は主要都市での無認可のストリートデモに対する取り締まり強化を発表した", cat: "ニュース", etym: "crack（割る）+ down（下に）。1920年代のニューススラングで、政府の「強硬な弾圧」を意味する。crack down on で句動詞化", syn: "clampdown(一斉取り締まり・より強硬), suppression(抑圧・より全面的), clamping down(同義句動詞)" },
  { en: "curfew", pos: "名詞", kana: "カーフュー", ja: "外出禁止令", ex: "A midnight curfew was imposed in the capital following three consecutive nights of rioting.", exJa: "3晩連続の暴動の後、首都に真夜中の外出禁止令が発令された", cat: "ニュース", etym: "フランス語 couvre-feu（火を覆う）。中世から夜間の火事防止の時間制限から由来。現在は夜間外出禁止令を指す", syn: "lockdown(都市全体の封鎖・COVID由来), blackout(夜間の灯火管制・戦時), stay-at-home order(自宅待機命令・より緩い)" },
  { en: "checkpoint", pos: "名詞", kana: "チェックポイント", ja: "検問所", ex: "Security forces set up additional checkpoints throughout the region to screen vehicles and passengers.", exJa: "治安部隊は車両と乗客をスクリーニングするため、地域全体に追加の検問所を設置した", cat: "ニュース", etym: "check（確認する）+ point。1940年代から軍事・警察用語として定着。身分確認や物品検査の地点を指す", syn: "roadblock(路上の障壁), border crossing(国境検査所・より正式), security point(セキュリティポイント・一般的)" },
  { en: "repatriation", pos: "名詞", kana: "リパトリエーション", ja: "本国送還", ex: "Humanitarian organizations are calling for the repatriation of refugees who wish to return home.", exJa: "人道支援団体は帰国を希望する難民の本国送還を呼びかけている", cat: "ニュース", etym: "ラテン語 patria（祖国）。re-（戻す）+ patria。難民や捕虜の本国帰還を指す。repatriate・patriot と同根", syn: "deportation(強制送還・より強制的), return(帰還・より広い), extradition(引き渡し・法的手続き)" },
  { en: "detention", pos: "名詞", kana: "ディテンション", ja: "拘束", ex: "Reports indicate that dozens of activists remain in detention without formal charges.", exJa: "報告によると、正式な起訴なしに数十人の活動家が拘束されたままである", cat: "ニュース", etym: "ラテン語 detinere（引き止める）。de-（から）+ tenere（持つ）。法的な身柄拘束を指す。detain・tenant と同根", syn: "arrest(逮捕・より刑事的), imprisonment(投獄・より長期), custody(身柄拘束・より行政的)" },
  { en: "detainee", pos: "名詞", kana: "ディテイニー", ja: "被拘束者", ex: "The detainee was released after questioning by local authorities.", exJa: "その被拘束者は地元当局の取り調べ後に釈放された", cat: "ニュース", etym: "detain（拘留する）+ -ee（～される人）。detain は de-（離す）+ tenere（保つ）で「自由を保たせない」という意味のラテン語由来。employee・refugee と同じ -ee の構造", syn: "prisoner（囚人・一般的）, captive（捕虜・拘束下にある人）, suspect（容疑者・調査段階）" },
  { en: "custody", pos: "名詞", kana: "カスタディ", ja: "拘留", ex: "The suspect remains in police custody pending trial.", exJa: "その容疑者は公判まで警察の拘留下にある", cat: "ニュース", etym: "ラテン語 custodia（守ること・監視）。custodian（管理人）・custom（慣習）と同根。「自由を失った状態で身柄を管理される」という意味へ", syn: "detention（拘束・法的手続き中）, imprisonment（投獄・受刑）, confinement（監禁・より広い概念）" },
  { en: "incursion", pos: "名詞", kana: "インカージョン", ja: "侵入", ex: "Military analysts reported cross-border incursions in the disputed territory.", exJa: "軍事アナリストたちは紛争地域での越境侵入を報告した", cat: "ニュース", etym: "ラテン語 incurrere（～に走り込む）= in-（中へ）+ currere（走る）。concur・occur・current と同じ curr 語根。軍事用語では「敵領への一時的な侵攻」を意味する", syn: "invasion（侵略・大規模な軍事侵攻）, raid（襲撃・一時的な侵入）, intrusion（侵入・より広い範囲）" },
  { en: "skirmish", pos: "名詞", kana: "スカーミッシュ", ja: "小競り合い", ex: "Border skirmishes between the two nations have escalated tensions.", exJa: "両国間の小競り合いが緊張をエスカレートさせた", cat: "ニュース", etym: "イタリア語 scaramuccia（軽騎兵の小競り合い）が語源。16世紀に軍事用語として英語に取り込まれた。大規模な戦闘ではなく「小規模で短時間の衝突」というニュアンス", syn: "clash（衝突・対立の接触）, engagement（交戦・軍事用語）, combat（戦闘・より激しい）" },
  { en: "shelling", pos: "名詞", kana: "シェリング", ja: "砲撃", ex: "The city endured weeks of heavy shelling before the ceasefire took effect.", exJa: "その都市は停戦が発効するまで数週間の激しい砲撃に耐えた", cat: "ニュース", etym: "shell（砲弾・貝殻）から動詞化。shell は貝殻の硬い外殻が砲弾の金属外殻に似ていることから転義。artillery・bombardment より「砲弾の連続投下」というニュアンス", syn: "bombardment（砲撃・集中的）, artillery fire（砲撃・より技術的）, barrage（集中砲火・短期的）" },
  { en: "crossfire", pos: "名詞", kana: "クロスファイア", ja: "銃撃戦", ex: "Civilians were caught in crossfire as fighting erupted in the downtown area.", exJa: "市街地で戦闘が勃発したため、市民は銃撃戦に巻き込まれた", cat: "ニュース", etym: "cross（交差）+ fire（銃火）。複数方向から同時に銃火を浴びせられる状況。「caught in the crossfire」で「巻き添えを食う」という慣用句にもなる", syn: "gunfire（銃撃・一般的）, firefight（銃撃戦・相互的）, exchange of fire（砲火交換・より中立的）" },
  { en: "frontline", pos: "名詞", kana: "フロントライン", ja: "前線", ex: "Soldiers on the frontline reported deteriorating conditions as winter approached.", exJa: "前線の兵士たちは冬が近づくにつれ悪化する状況を報告した", cat: "ニュース", etym: "front（戦線・前面）+ line（線）。比喩的には「激動の最前線」の意味でも使われる。「on the frontline」で「最も危険・重要な場所に」というニュアンス", syn: "battlefield（戦場・より広い概念）, front（前線・軍事用語）, line of contact（接触線・より正式）" },
  { en: "backchannel", pos: "名詞", kana: "バックチャネル", ja: "秘密交渉ルート", ex: "Diplomats are using backchannel communications to explore ceasefire possibilities.", exJa: "外交官たちは停戦の可能性を探るため、秘密交渉ルートを通じて連絡を取っている", cat: "ニュース", etym: "back（裏側の）+ channel（経路）。公式ルートではなく「目立たない密室の通路」という意味。外交用語として、キッシンジャーやベーカーなど歴史的な秘密交渉で有名", syn: "covert channel（秘密経路・隠密性重視）, backroom negotiation（裏交渉・より包括的）" },
  { en: "deescalation", pos: "名詞", kana: "ディエスカレーション", ja: "緊張緩和", ex: "International observers urged both parties to pursue deescalation measures immediately.", exJa: "国際オブザーバーは両当事者に直ちに緊張緩和措置を取るよう促した", cat: "ニュース", etym: "de-（逆に）+ escalation（段階的な上昇）。escalate は escalator（エスカレーター）と同じ語根。「エスカレーターを下る」ように緊張を段階的に低下させる", syn: "détente（雪解け・政治的な関係改善）, cooling-off（冷却期間・より短期的）, reduction of tensions（緊張軽減・より正式）" },
  { en: "reconciliation", pos: "名詞", kana: "リコンシリエーション", ja: "和解", ex: "The Truth and Reconciliation Commission aims to heal historical wounds between communities.", exJa: "真実和解委員会はコミュニティ間の歴史的傷を癒すことを目指している", cat: "ニュース", etym: "re-（再び）+ conciliation（仲直り）。concile はラテン語 conciliare（調和させる）。account・concur・council と同根。「再び心を一つにする」という意味", syn: "settlement（解決・紛争終結）, peace agreement（平和協定・より正式）, truce（休戦・一時的）" },
  { en: "normalization", pos: "名詞", kana: "ノーマライゼーション", ja: "関係正常化", ex: "The two countries signed an agreement on the normalization of trade relations.", exJa: "両国は貿易関係の正常化に関する協定に署名した", cat: "ニュース", etym: "normal（通常の・標準的な）+ -ize（～にする）。normal はラテン語 norma（定規・規準）から。「関係が通常の状態に戻る」というニュアンス", syn: "rapprochement（関係改善・より感情的）, regularization（規則化・より広い概念）" },
  { en: "rapprochement", pos: "名詞", kana: "ラプロシュマン", ja: "関係改善", ex: "Recent diplomatic visits signal a possible rapprochement between the estranged nations.", exJa: "最近の外交訪問は疎遠になっていた国々の関係改善の可能性を示している", cat: "ニュース", etym: "フランス語 rapprochement（近づくこと）。rapprocher = re-（再び）+ approcher（近い）。normalization より「感情的・関係的な接近」という温かみがある", syn: "reconciliation（和解・より深い関係修復）, détente（雪解け・より政治的）, thaw（融解・比喩的）" },
  { en: "neutrality", pos: "名詞", kana: "ニュートラリティ", ja: "中立", ex: "The government declared its neutrality in the regional conflict.", exJa: "その政府は地域紛争における中立性を宣言した", cat: "ニュース", etym: "neutral（中立的な）+ -ity（状態）。neutral はラテン語 neutralis = ne-（どちらでもない）+ uterque（どちらか）。Switzerland が歴史的に標榜する国是", syn: "non-alignment（非同盟・政治的立場）, impartiality（公平性・より価値中立的）, non-interference（不干渉・より積極的）" },
  { en: "hegemony", pos: "名詞", kana: "ヘゲモニー", ja: "覇権", ex: "The article examines American hegemony in the post-Cold War international order.", exJa: "その論文は冷戦後の国際秩序におけるアメリカの覇権を検証している", cat: "ニュース", etym: "ギリシャ語 hegemonía（指導権・支配権）。hegemon（覇権国）から派生。古代ギリシャのスパルタやアテネの覇権競争に由来する政治学用語", syn: "dominance（優位・より広い範囲）, supremacy（最高権力・より絶対的）, leadership（指導力・より共意的）" },
  { en: "doctrine", pos: "名詞", kana: "ドクトリン", ja: "基本方針", ex: "The Monroe Doctrine prohibited European intervention in the Americas.", exJa: "モンロー・ドクトリンはアメリカ大陸へのヨーロッパの干渉を禁止した", cat: "ニュース", etym: "ラテン語 doctrina（教え・学説）。doctor（医者・博士）と同根。「教えられた基本原理」が転じて「国家や組織の根本方針」という意味に拡張", syn: "policy（政策・実行重視）, principle（原則・より基礎的）, ideology（イデオロギー・思想体系）" },
  { en: "ultimatum", pos: "名詞", kana: "アルティメイタム", ja: "最後通告", ex: "The government issued an ultimatum demanding the immediate withdrawal of troops from the disputed territory.", exJa: "政府は紛争地域からの即座の軍隊撤退を要求する最後通告を突きつけた。", cat: "ニュース", etym: "ラテン語 ultimus（最後の）に由来。「最後の」という意味の形容詞が名詞化され、譲歩の余地がない最終的な要求を指すようになった。ultimate と同根", syn: "demand（要求・最終要求）, threat（脅迫・強制的なニュアンス）, warning（警告・より穏やかな警示）" },
  { en: "oversight", pos: "名詞", kana: "オーバーサイト", ja: "監督", ex: "Congressional oversight of the intelligence agency ensures accountability and prevents abuse of power.", exJa: "情報機関に対する議会の監督は、説明責任を確保し権力濫用を防止する。", cat: "ニュース", etym: "over（上から）+ sight（見る）→「見落とし」と「監督」の両義を持つ。oversight committee のように法的監視を意味し、同時に oversight error のように不注意による見落としも表す二重性が特徴", syn: "supervision（監督・日常的な管理）, governance（統治・包括的な統治体制）, audit（監査・財務的検査）" },
  { en: "ratification", pos: "名詞", kana: "ラティフィケーション", ja: "批准", ex: "The treaty will enter into force only after ratification by a majority of member states.", exJa: "条約は加盟国の多数による批准後にのみ発効する。", cat: "ニュース", etym: "ラテン語 ratus（確認した）+ facere（する）。条約や協定を公式に「確認して有効にする」という意味。ratify の名詞形で、国家が国際合意に法的拘束力を与える行為", syn: "approval（承認・一般的な認可）, confirmation（確認・より形式的な確定）, endorsement（支持・公式な支持表明）" },
  { en: "annexation", pos: "名詞", kana: "アネクセーション", ja: "併合", ex: "The international community condemned the annexation of the territory as a violation of sovereignty.", exJa: "国際社会は領土の併合を主権侵害として非難した。", cat: "ニュース", etym: "ラテン語 annectere（つなぐ・添付する）に由来。領土を「つなぎ合わせて」自国に組み込む行為。annex の名詞形で、国際紛争の中心的なテーマとなることが多い", syn: "acquisition（買収・資産獲得）, incorporation（編入・組織への統合）, occupation（占領・軍事的占領）" },
  { en: "statehood", pos: "名詞", kana: "ステートフッド", ja: "国家としての地位", ex: "Palestinian leaders have long sought international recognition of statehood.", exJa: "パレスチナの指導者たちは長年、国家地位の国際的承認を求めてきた。", cat: "ニュース", etym: "state（国家）+ hood（身分・状態）。ある地域が独立国家として認められる法的・政治的地位。hood は boyhood・childhood のように「～の時代・状態」を示す接尾辞", syn: "sovereignty（主権・国家の自主性）, independence（独立・政治的独立）, nationhood（国家性・民族的統一）" },
  { en: "plenary", pos: "名詞", kana: "プレナリー", ja: "本会議", ex: "The European Parliament held a plenary session to debate the new climate legislation.", exJa: "欧州議会は新しい気候法制について討論するための本会議を開催した。", cat: "ニュース", etym: "ラテン語 plenus（満杯の・完全な）に由来。plenary session は全構成員が参加する「完全な」会議。plenum・plenty と同根", syn: "assembly（集会・総合的な集まり）, session（会期・一定期間の会議）, convention（大会・大規模な集会）" },
  { en: "incumbent", pos: "名詞", kana: "インカンベント", ja: "現職者", ex: "The incumbent mayor faces a strong challenger in next month's election.", exJa: "現職の市長は来月の選挙で有力な対抗馬に直面している。", cat: "ニュース", etym: "ラテン語 incumbere（身をかがめて座る・職にある）。in（中に）+ cumbere（寝転ぶ）が原義で、「地位の中に居座っている者」。incumbency は任期を意味する", syn: "holder（保持者・役職保持者一般）, officeholder（官職者・公務職の保持者）, sitting official（現職官吏・より形式的）" },
  { en: "turnout", pos: "名詞", kana: "ターンアウト", ja: "投票率", ex: "Election officials reported a record turnout of 68 percent in the presidential election.", exJa: "選挙管理委員会は大統領選挙で68パーセントという過去最高の投票率を報告した。", cat: "ニュース", etym: "turn out（現れる・出かける）の名詞形。選挙投票所に「現れた」有権者の数。実際には投票に加えて「生産量」や「装備」の意味でも使われる多義語", syn: "participation（参加・参加率一般）, attendance（出席・物理的な出席）, voter engagement（投票関与・市民参加度）" },
  { en: "municipality", pos: "名詞", kana: "ミュニシパリティ", ja: "自治体", ex: "Local municipalities are responsible for managing water supply and waste management systems.", exJa: "地方自治体は水道供給と廃棄物処理システムの管理に責任を負う。", cat: "ニュース", etym: "ラテン語 municeps（市民）+ -ality（～性）。古代ローマで市民権を持つ都市の概念に由来し、現在は地方自治権を持つ自治体を指す", syn: "local government（地方自治体・行政単位）, city（都市・都市規模の地域）, district（地区・より小規模な区域）" },
  { en: "ordinance", pos: "名詞", kana: "オーディナンス", ja: "条例", ex: "The city council passed a new ordinance banning plastic bags at retail stores.", exJa: "市議会は小売店でのビニール袋禁止を定める新しい条例を可決した。", cat: "ニュース", etym: "ラテン語 ordinare（秩序立てる）に由来。都市や自治体が秩序を保つために制定する法令。ordain（聖職に就任させる）と同根", syn: "regulation（規則・一般的な法的規制）, statute（法令・より上位の法律）, bylaw（細則・組織内規則）" },
  { en: "bylaw", pos: "名詞", kana: "バイロー", ja: "細則", ex: "The company's bylaws specify the voting rights of shareholders and the responsibilities of board members.", exJa: "会社の細則は株主の議決権および取締役の責務を明記している。", cat: "ニュース", etym: "by（脇の・二次的な）+ law（法）→「副次的な法規」。組織や自治体が本法に基づいて定める運営細則。主に英国とカナダで一般的な用語", syn: "regulation（規則・組織の運営規則）, rule（規則・より一般的な規定）, provision（条項・特定の規定事項）" },
  { en: "jurisprudence", pos: "名詞", kana: "ジュリスプルーデンス", ja: "法理学", ex: "Modern jurisprudence debates whether artificial intelligence should have legal personhood.", exJa: "現代の法理学は人工知能が法的人格を持つべきかについて議論している。", cat: "ニュース", etym: "ラテン語 juris（法の）+ prudentia（知識・思慮）。法学の哲学的・理論的側面を扱う学問。prudent（慎重な）と同根", syn: "legal philosophy（法哲学・思想的側面）, case law（判例法・先例に基づく法）, legal doctrine（法学説・学派の理論）" },
  { en: "adjudication", pos: "名詞", kana: "アジュディケーション", ja: "司法判断", ex: "The international court's adjudication in the border dispute was binding on both nations.", exJa: "国際裁判所による国境紛争に関する司法判断は両国を拘束するものであった。", cat: "ニュース", etym: "ラテン語 adjudicare（判決を下す）。ad（～へ）+ judicare（判断する）が原義。judge・judicial と同根で、裁判所による公式な判定を意味する", syn: "judgment（判決・裁判所の決定）, ruling（判断・より口語的な決定）, determination（決定・法的な決定）" },
  { en: "litigation", pos: "名詞", kana: "リティゲーション", ja: "訴訟", ex: "The company avoided costly litigation by reaching a settlement with the plaintiff.", exJa: "会社は原告との和解に至ることで高額の訴訟費用を回避した。", cat: "ニュース", etym: "ラテン語 litigare（争う・裁判にかける）。lis（争い）+ agere（行動する）が原義。訴訟手続きという形式化された法的紛争解決手段", syn: "lawsuit（訴訟・法廷闘争一般）, legal action（法的措置・より広い法的行為）, dispute resolution（紛争解決・より包括的）" },
  { en: "settlement", pos: "名詞", kana: "セトルメント", ja: "和解金", ex: "The two parties reached a settlement of $50 million to resolve the class-action lawsuit.", exJa: "両当事者は集団訴訟を解決するための5000万ドルの和解金に合意した。", cat: "ニュース", etym: "settle（決着をつける）の名詞形。settle は「沈殿する」が原義で、「争いが沈殿して落ち着く」という意味に転じた。settlement agreement で法的拘束力を持つ", syn: "agreement（合意・紛争解決の取決め）, compensation（補償・金銭的賠償）, payout（支払い・より口語的な金銭支払い）" },
  { en: "armory", pos: "名詞", kana: "アーモリー", ja: "兵器庫", ex: "The military seized weapons from an underground armory suspected of supplying militant groups.", exJa: "軍は過激派勢力への供給を疑われている地下の兵器庫から武器を押収した。", cat: "ニュース", etym: "ラテン語 arma（武器）に由来。armor（鎧）と同根で、武器や防具を保管する場所の意味。", syn: "arsenal（兵器・弾薬の貯蔵庫）, weapons depot（武器保管所・より一般的）" },
  { en: "warship", pos: "名詞", kana: "ウォーシップ", ja: "軍艦", ex: "Several warships from allied nations are conducting joint exercises in the contested waters.", exJa: "同盟国の複数の軍艦が係争海域で共同演習を実施している。", cat: "ニュース", etym: "war（戦争）+ ship（船）の単純合成。近代の軍艦は19世紀の蒸気機関の登場で劇的に進化した。", syn: "battleship（戦艦・主力艦）, destroyer（駆逐艦・小型艦）, cruiser（巡洋艦・中型艦）" },
  { en: "frigate", pos: "名詞", kana: "フリゲート", ja: "フリゲート艦", ex: "The frigate was dispatched to monitor suspicious vessel activity near the shipping lanes.", exJa: "そのフリゲート艦は海上輸送路付近の不審な船舶活動を監視するため派遣された。", cat: "ニュース", etym: "イタリア語 fregata に由来。17世紀の地中海で活躍した中型帆船が語源で、現代でも多目的護衛艦として各国海軍の主力。", syn: "corvette（コルベット艦・さらに小型）, patrol vessel（哨戒艦・一般的）" },
  { en: "submarine", pos: "名詞", kana: "サブマリン", ja: "潜水艦", ex: "The nuclear submarine conducted a submerged patrol lasting several weeks without surfacing.", exJa: "その原子力潜水艦は浮上せずに数週間続く水中パトロールを実施した。", cat: "ニュース", etym: "ラテン語 sub（下に）+ mare（海）→「海の下」。19世紀の Industrial Revolution で実用化された revolutionary な軍事兵器。", syn: "sub（潜水艦の略式呼称）, underwater vessel（水中船舶・より形式的）" },
  { en: "airspace", pos: "名詞", kana: "エアスペース", ja: "領空", ex: "The country warned that any military aircraft entering its airspace without permission would be shot down.", exJa: "その国は許可なく領空に進入する軍用機は撃墜されると警告した。", cat: "ニュース", etym: "air（空気）+ space（空間）の合成語。20世紀初頭の航空機登場に伴い、領土と同様に主権が及ぶ空域を指す概念として確立。", syn: "territorial air（領空・より形式的）" },
  { en: "coastline", pos: "名詞", kana: "コーストライン", ja: "海岸線", ex: "Rising sea levels are gradually eroding the coastline, forcing communities to relocate inland.", exJa: "海面上昇が海岸線を徐々に浸食し、地域住民の内陸への移住を余儀なくさせている。", cat: "ニュース", etym: "coast（海岸）+ line（線）の合成。coast はラテン語 costa（肋骨）から、陸地の「肋骨」のような縁という概念。", syn: "coast（海岸・より一般的）, shore（岸・陸地寄り）" },
  { en: "peninsula", pos: "名詞", kana: "ペニンシュラ", ja: "半島", ex: "The peninsula has become a flashpoint for regional tensions due to its strategic geographic location.", exJa: "その半島は戦略的な地理的位置により地域紛争の焦点となっている。", cat: "ニュース", etym: "ラテン語 paene（ほぼ）+ insula（島）→「ほぼ島」。三方を水に囲まれた陸地を指す地理用語。", syn: "cape（岬・より小規模）, promontory（岬・より格式的）" },
  { en: "strait", pos: "名詞", kana: "ストレイト", ja: "海峡", ex: "Tensions have escalated over control of the strategic strait, with multiple nations deployed nearby.", exJa: "戦略的な海峡の支配をめぐって緊張が高まり、複数国が近くに展開している。", cat: "ニュース", etym: "ラテン語 strictus（狭い）に由来。2つの陸地に挟まれた狭い海域を指し、古くから交易路・軍事要衝として重要。", syn: "channel（水道・より広い）, passage（通路・一般的）" },
  { en: "maritime", pos: "名詞", kana: "マリタイム", ja: "海上の", ex: "The report highlights growing maritime disputes in the region and calls for international mediation.", exJa: "その報告書は同地域での増加する海上紛争に着目し、国際仲裁を求めている。", cat: "ニュース", etym: "ラテン語 mare（海）+ -time（関連する）。海に関する法律・商業・戦略を指す形容詞で、International Maritime Law など国際紛争でも頻出。", syn: "naval（海軍の・軍事寄り）, oceanic（海洋の・科学寄り）, nautical（船舶関連の）" },
  { en: "inspectorate", pos: "名詞", kana: "インスペクトレート", ja: "監察機関", ex: "The UN nuclear inspectorate has access to Iranian facilities to verify compliance with the agreement.", exJa: "UN核監察機関はイランの施設へのアクセス権を持ち、協定遵守を検証する。", cat: "ニュース", etym: "ラテン語 inspicere（調べる）+ -ate（機関）。inspect と同根で、政府機関による査察・検査を行う公式な部門を指す。", syn: "inspection body（検査機関・より中立的）, oversight agency（監督機関・より広い）" },
  { en: "taskforce", pos: "名詞", kana: "タスクフォース", ja: "特別部隊", ex: "A joint taskforce was assembled to combat human trafficking networks across the border region.", exJa: "国境地域の人身売買ネットワークに対抗するため合同特別部隊が編成された。", cat: "ニュース", etym: "task（任務）+ force（部隊）の合成語。特定の目標遂行のため編成された臨時的な部隊編制で、軍事・警察用語として定着。", syn: "strike force（攻撃部隊・攻撃的）, special unit（特別部隊・より一般的）" },
  { en: "persecution", pos: "名詞", kana: "パーセキューション", ja: "迫害", ex: "Human rights organizations documented systematic persecution of religious minorities in the country.", exJa: "人権団体はその国の宗教的少数派への組織的な迫害を記録した。", cat: "ニュース", etym: "ラテン語 persequi（追い続ける）に由来。per-（徹底的に）+ sequi（従う）で、特定の集団を継続的に攻撃・抑圧する行為。", syn: "oppression（抑圧・より継続的・構造的）, harassment（嫌がらせ・より日常的・軽微）" },
  { en: "oppression", pos: "名詞", kana: "オプレッション", ja: "抑圧", ex: "The regime's oppression of dissent has prompted international condemnation and sanctions.", exJa: "その政権の言論抑圧は国際的な非難と制裁を招いた。", cat: "ニュース", etym: "ラテン語 opprimere（押さえつける）に由来。op-（反対に）+ premere（押す）で、政治権力による広範な支配と自由の制限を指す。", syn: "suppression（抑制・より意図的・政治的）, repression（抑圧・より無意識的）" },
  { en: "massacre", pos: "名詞", kana: "マサカー", ja: "虐殺", ex: "Investigators are documenting evidence of a potential massacre in the conflict zone for the International Criminal Court.", exJa: "調査官は国際刑事裁判所のため紛争地域での潜在的な虐殺の証拠を記録している。", cat: "ニュース", etym: "フランス語 macher（切り刻む）説が有力。武装勢力による無差別・大量殺害を指す歴史的に重い語。", syn: "slaughter（殺戮・動物にも使える）, atrocity（暴虐・より広い範囲の残虐行為）" },
  { en: "donor", pos: "名詞", kana: "ドナー", ja: "支援提供者", ex: "Major donor countries pledged additional humanitarian aid at the international conference on Syria.", exJa: "主要援助国はシリアに関する国際会議で追加的な人道支援を約束した。", cat: "ニュース", etym: "ラテン語 donare（与える）に由来。donation と同根で、金銭・臓器・血液などを提供する人、また開発援助国を指す。", syn: "benefactor（恩人・より個人的）, contributor（貢献者・より一般的）, sponsor（スポンサー・対価が伴う）" },
  { en: "funding", pos: "名詞", kana: "ファンディング", ja: "資金供給", ex: "The government announced a new funding initiative to support renewable energy projects across the region.", exJa: "政府は地域全体の再生可能エネルギープロジェクトを支援する新たな資金供給イニシアティブを発表した", cat: "ニュース", etym: "ラテン語 fundus（底・基礎）に由来。fund は「資金を供給する基盤」という意味。foundation と同根", syn: "financing（資金調達・より広い範囲）, subsidy（補助金・政府支援）, grant（助成金・返済不要）" },
  { en: "allocation", pos: "名詞", kana: "アロケーション", ja: "配分", ex: "The budget allocation for healthcare has increased by 15% compared to last year.", exJa: "医療予算の配分は前年比で15%増加した", cat: "ニュース", etym: "ラテン語 allocare（〜に割り当てる）から。ad（〜へ）+ locare（場所を与える）→「正当な場所に配分する」", syn: "distribution（配布・より広い範囲）, apportionment（割り当て・公式な配分）, assignment（割り当て・人や役割へ）" },
  { en: "distribution", pos: "名詞", kana: "ディストリビューション", ja: "配布", ex: "Aid organizations face challenges in the distribution of food supplies to remote villages.", exJa: "援助団体は離島の村への食糧供給の配布に課題を抱えている", cat: "ニュース", etym: "ラテン語 distribuere（〜に分配する）から。dis（分散）+ tribuere（割り当てる）。tribute・attribute と同根", syn: "allocation（配分・限定的）, dispersal（分散・広く散らす）, delivery（配達・特定地点へ）" },
  { en: "corridor", pos: "名詞", kana: "コリドー", ja: "回廊", ex: "Humanitarian officials negotiated a safe corridor for civilians to escape the conflict zone.", exJa: "人道支援官は市民が紛争地域を脱出するための安全な回廊について交渉した", cat: "ニュース", etym: "イタリア語 corridore（走る人）→「通路」の意味に。近代政治では「green corridor（人道回廊）」などで政治的な通路を指す", syn: "passage（通路・一般的）, hallway（廊下・建物内）, aisle（通路・列の間）" },
  { en: "evacuee", pos: "名詞", kana: "イバキュイー", ja: "避難民", ex: "Over 10,000 evacuees are still waiting in temporary shelters for news about returning home.", exJa: "1万人以上の避難民が帰宅の知らせを待ちながら仮設シェルターで過ごしている", cat: "ニュース", etym: "ラテン語 evacuare（空にする）から。e（外に）+ vacuus（空の）。vacuum と同根。-ee は受ける側の人を指す", syn: "refugee（難民・より広い範囲・政治的背景）, displaced person（立ち退き者・紛争や災害で）" },
  { en: "remittance", pos: "名詞", kana: "リミッタンス", ja: "送金", ex: "Remittances from overseas workers now account for nearly 20% of the country's GDP.", exJa: "海外労働者からの送金は現在、国のGDPの約20%を占めている", cat: "ニュース", etym: "ラテン語 remittere（送り戻す）から。re（戻す）+ mittere（送る）。transmit・missile と同根", syn: "transfer（送金・一般的）, payment（支払い・より広い範囲）, wire（送電・電信送金）" },
  { en: "smuggler", pos: "名詞", kana: "スマグラー", ja: "密輸業者", ex: "Authorities arrested a major smuggler who had been operating across three countries.", exJa: "当局は3カ国に及ぶ密輸活動を行っていた大物密輸業者を逮捕した", cat: "ニュース", etym: "オランダ語 smokkelen（密輸する）またはドイツ語 schmuggeln に由来。17世紀の海運用語から。-er は「〜する人」", syn: "trafficker（人身売買・違法な商取引）, bootlegger（密造酒の製造者・禁止物品）" },
  { en: "trafficking", pos: "名詞", kana: "トラフィッキング", ja: "不正取引", ex: "International efforts to combat human trafficking have intensified following the UN summit.", exJa: "国連サミット後、人身売買に対抗する国際的な取り組みが強化された", cat: "ニュース", etym: "イタリア語 traffico（商取引）に由来。16世紀の貿易用語から。traffic の動名詞形で「違法な取引」の意味が強まった", syn: "smuggling（密輸・同等だが個別物品を指すことが多い）, contraband（密輸品・違法物品そのもの）" },
  { en: "piracy", pos: "名詞", kana: "パイラシー", ja: "海賊行為", ex: "Somali piracy has declined significantly since naval patrols increased in the region.", exJa: "この地域での海軍パトロール増加以来、ソマリア沖の海賊行為は著しく減少した", cat: "ニュース", etym: "ギリシャ語 peirein（試す・襲う）→ ラテン語 pirata。「略奪者」を意味する海運用語。古来から存在する違法行為", syn: "theft（盗難・一般的）, hijacking（乗っ取り・特に輸送手段）, robbery（強盗・より暴力的）" },
  { en: "hostility", pos: "名詞", kana: "ホスティリティ", ja: "敵対行為", ex: "Both sides agreed to cease hostilities and begin peace negotiations next month.", exJa: "双方は敵対行為を停止し、来月から平和交渉を開始することに合意した", cat: "ニュース", etym: "ラテン語 hostis（敵）から。hostility は「敵意を持った状態」。host（東主人）と同根だが、古義では「敵陣営」を指した", syn: "aggression（攻撃・より積極的）, enmity（敵意・感情的）, antagonism（対立・意見の相違）" },
  { en: "deterrent", pos: "名詞", kana: "ディターラント", ja: "抑止要因", ex: "Military analysts argue that the nuclear arsenal serves as a strategic deterrent.", exJa: "軍事アナリストは核兵器が戦略的な抑止要因として機能していると主張している", cat: "ニュース", etym: "ラテン語 deterrere（威して遠ざける）から。de（離す）+ terrere（怖がらせる）。deter の名詞形で「敵を怯ませるもの」", syn: "obstacle（障害・物理的）, disincentive（抑止・マイナス動機付け）, preventive measure（予防措置・より広い範囲）" },
  { en: "countermeasure", pos: "名詞", kana: "カウンターメジャー", ja: "対抗措置", ex: "The government implemented new countermeasures to prevent cyberattacks on critical infrastructure.", exJa: "政府は重要インフラへのサイバー攻撃を防ぐための新たな対抗措置を実施した", cat: "ニュース", etym: "counter（対抗する）+ measure（手段）の合成語。counter はラテン語 contra（反対）に由来。政治・軍事用語として20世紀に確立", syn: "response（対応・一般的）, retaliation（報復・より積極的）, defensive measure（防衛措置・守りの姿勢）" },
  { en: "standstill", pos: "名詞", kana: "スタンドスティル", ja: "行き詰まり", ex: "Negotiations reached a standstill after disagreements over trade tariffs intensified.", exJa: "貿易関税をめぐる意見の不一致が激化し、交渉は行き詰まった", cat: "ニュース", etym: "stand（立つ）+ still（止まった状態）の合成語。「完全に動きが止まった状態」を指す。ビジネス・政治用語として頻出", syn: "deadlock（膠着状態・双方が譲らない）, impasse（身動きが取れない状況・外交的）, stalemate（膠着・同等の力関係）" },
  { en: "withdrawal", pos: "名詞", kana: "ウィズドローアル", ja: "撤退", ex: "The country announced its withdrawal from the international agreement effective immediately.", exJa: "その国は国際協定からの即時撤退を発表した", cat: "ニュース", etym: "with（後ろへ）+ draw（引く）→「後ろへ引く」。withdraw は中世英語から。軍事・政治で撤退の意味で多用", syn: "retreat（撤退・戦術的）, pullout（引き揚げ・より日常的）, exit（退出・一般的）" },
  { en: "customs", pos: "名詞", kana: "カスタムズ", ja: "税関", ex: "Customs officials discovered contraband hidden in shipping containers at the port.", exJa: "税関職員は港の海運コンテナに隠された密輸品を発見した", cat: "ニュース", etym: "ラテン語 consuetudo（習慣・慣例）から。中世では「商人の習慣的な税」を指す。custom（慣習）と同語源", syn: "border control（国境管理・より広い範囲）, tariff authority（関税当局・税徴収に限定）" },
  { en: "boycott", pos: "名詞", kana: "ボイコット", ja: "不買運動", ex: "Consumer groups are calling for a boycott of the company over environmental concerns.", exJa: "消費者団体は環境問題を理由に、その企業に対する不買運動を呼びかけている", cat: "ニュース", etym: "19世紀アイルランドの地主チャールズ・ボイコット（Charles Boycott）が小作農から拒否された事件に由来。人名が普通名詞化した珍しい例", syn: "sanction（制裁・公式な経済圧力）, embargo（禁輸・政府レベルの貿易制限）, blacklist（ブラックリスト・個人や企業の排除）" },
  { en: "quarantine", pos: "名詞", kana: "クアランティーン", ja: "隔離措置", ex: "Health authorities have imposed a quarantine on the affected region to prevent disease spread.", exJa: "保健当局は病気の拡大を防ぐため、その地域に隔離措置を敷いた", cat: "ニュース", etym: "イタリア語 quaranta giorni（40日間）。中世ベネチアが疫病船を40日間隔離した慣行に由来", syn: "isolation（孤立・より広い隔離状態）, lockdown（ロックダウン・地域全体の封鎖）, confinement（監禁・より強制的なニュアンス）" },
  { en: "monitoring", pos: "名詞", kana: "モニタリング", ja: "監視活動", ex: "International observers are monitoring the election to ensure transparency.", exJa: "国際監視団は透明性を確保するため、その選挙の監視活動を行っている", cat: "ニュース", etym: "ラテン語 monere（警告する）が語源。monitor は元々「警告者」の意。同根語: admonish, monument", syn: "surveillance（監視・継続的な観察）, observation（観測・より客観的）, supervision（監督・指導を含む）" },
  { en: "sanctuary", pos: "名詞", kana: "サンクチュアリ", ja: "保護区域", ex: "The nature reserve serves as a sanctuary for endangered species.", exJa: "その自然保護区は絶滅危機種の保護区域として機能している", cat: "ニュース", etym: "ラテン語 sanctus（神聖な）。元々は教会内の聖域で、追手から逃げた者が保護される場所だった", syn: "refuge（避難所・一時的な保護）, haven（避難地・安全な場所）, preserve（保護区・自然環境の保全を強調）" },
  { en: "insurgents", pos: "名詞", kana: "インサージェンツ", ja: "反乱勢力", ex: "Insurgents have launched coordinated attacks across three provinces.", exJa: "反乱勢力は3つの州で協調的な攻撃を仕掛けた", cat: "ニュース", etym: "ラテン語 insurgere（立ち上がる）= in-（中へ）+ surgere（盛り上がる）。surge, surge と同根", syn: "rebels（反政府勢力・より広い造反集団）, militants（戦闘員・イデオロギー的色彩）, guerrillas（ゲリラ・非正規戦闘戦術）" },
  { en: "uprising", pos: "名詞", kana: "アップライジング", ja: "蜂起", ex: "The uprising was sparked by economic hardship and political repression.", exJa: "その蜂起は経済的困窮と政治的弾圧によって引き起こされた", cat: "ニュース", etym: "up（上へ）+ rising。insurgents と意味は近いが、uprising は民衆の素朴な蜂起というニュアンス", syn: "rebellion（反乱・組織的な反抗）, revolt（反発・より激しい抵抗）, insurrection（暴動・武装蜂起）" },
  { en: "standoff", pos: "名詞", kana: "スタンドオフ", ja: "にらみ合い", ex: "A tense military standoff continues along the border.", exJa: "国境沿いで緊迫した軍事的にらみ合いが続いている", cat: "ニュース", etym: "stand off（対抗する・距離を保つ）が複合名詞化。military standoff は両軍が膠着状態", syn: "stalemate（膠着状態・動きが取れない）, deadlock（行き止まり・交渉が進まない）, impasse（動きが取れない状況・より正式）" },
  { en: "truce line", pos: "名詞", kana: "トゥルースライン", ja: "停戦ライン", ex: "Both sides agreed to withdraw forces behind the truce line.", exJa: "両陣営は停戦ラインの後方に部隊を撤退させることに合意した", cat: "ニュース", etym: "truce はラテン語 treuga（停戦約定）に由来。中世から使われるヨーロッパの軍事用語", syn: "ceasefire boundary（停戦境界）, demilitarized zone（非武装地帯・DMZ）, armistice line（休戦線・より正式）" },
  { en: "peace process", pos: "名詞", kana: "ピースプロセス", ja: "和平プロセス", ex: "International mediators are attempting to restart the peace process.", exJa: "国際仲裁者は和平プロセスの再開を試みている", cat: "ニュース", etym: "peace（平和）は古フランス語 pais ← ラテン語 pax。process（進行・手続き）と組み合わさったニュース用語", syn: "peace talks（平和交渉・より直接的）, reconciliation（和解・対立の修復）, settlement（解決・紛争の終結）" },
  { en: "demarcation", pos: "名詞", kana: "ディマーケーション", ja: "境界画定", ex: "The treaty established a clear demarcation between the two territories.", exJa: "その条約は2つの領土の間に明確な境界画定を確立した", cat: "ニュース", etym: "フランス語 démarcation = dé-（分離）+ marquer（標示する）。marque, mark と同根", syn: "boundary（境界線・一般的）, delineation（境界線の明示・より形式的）, delimitation（境界確定・国際法用語）" },
  { en: "red line", pos: "名詞", kana: "レッドライン", ja: "越えてはならない一線", ex: "The government warned that military intervention would cross a red line.", exJa: "政府は軍事介入が越えてはならない一線を超えるだろうと警告した", cat: "ニュース", etym: "地図上の引き直されない赤い線がメタファーに。イギリスの軍事地図用語が政治的に転用された", syn: "threshold（閾値・超えると許されない点）, limit（限界・許容の境目）, breaking point（限界点・我慢の限界）" },
  { en: "proxy", pos: "名詞", kana: "プロキシ", ja: "代理勢力", ex: "The conflict has become a proxy war between regional powers.", exJa: "その紛争は地域大国間の代理勢力による戦争と化してしまった", cat: "ニュース", etym: "ラテン語 procurare（代理処理する）→ 中世英語 proxy（委任状）。本来は法律用語", syn: "surrogate（代理人・正規の代理）, substitute（代替物・より一般的）, agent（代理人・行動する者）" },
  { en: "firepower", pos: "名詞", kana: "ファイアパワー", ja: "火力", ex: "The military superiority was due to greater firepower and advanced weaponry.", exJa: "軍事的優位は大きな火力と先進兵器によるものだった", cat: "ニュース", etym: "fire（砲火）+ power（力）。19世紀の軍事用語から現代まで軍事報道で使われ続ける", syn: "weaponry（武装・兵器全般）, arsenal（兵器庫・保有兵器）, armament（武装・軍事力）" },
  { en: "mobilization", pos: "名詞", kana: "モビライゼーション", ja: "動員", ex: "The government announced a large-scale mobilization of troops.", exJa: "政府は大規模な兵力動員を発表した", cat: "ニュース", etym: "フランス語 mobilisation ← mobile（可動的）。mobile は動詞 move と語族を共にする", syn: "deployment（配備・兵力配置）, recruitment（採用・人員確保）, activation（発動・機能の開始）" },
  { en: "conscription", pos: "名詞", kana: "コンスクリプション", ja: "徴兵", ex: "The government introduced mandatory conscription amid rising tensions.", exJa: "政府は緊張の高まりの中で強制徴兵制を導入した", cat: "ニュース", etym: "ラテン語 conscribere = con-（一緒に）+ scribere（書く）。登録名簿に名を書く→強制徴募", syn: "draft（徴兵・米国用語）, enlistment（入隊・志願制）, compulsory service（強制兵役・より強制的）" },
  { en: "demobilization", pos: "名詞", kana: "ディモビライゼーション", ja: "動員解除", ex: "The government announced a phased demobilization of troops following the ceasefire agreement.", exJa: "政府は休戦合意後の段階的な動員解除を発表した。", cat: "ニュース", etym: "ラテン語 de（逆・解く）+ mobilize（動員する）。mobilize は movable（動かせる）と同根で、「動きの自由を取り戻す」という意味合い", syn: "withdrawal（撤退・引き揚げ）, disarmament（軍縮）, decommissioning（廃止・配置転換）" },
  { en: "safe zone", pos: "名詞", kana: "セーフゾーン", ja: "安全地帯", ex: "The UN established a safe zone to protect civilians from ongoing violence in the region.", exJa: "国連は当該地域の暴力から民間人を保護するため安全地帯を設置した。", cat: "ニュース", etym: "safe は古フランス語 sauf（守られた）に由来。zone はギリシャ語 zonē（帯・地帯）から。紛争地で民間人が保護される物理的な「帯状の領域」", syn: "demilitarized zone（非武装地帯・DMZ）, neutral territory（中立地帯）, protective area（保護区域）" },
  { en: "buffer zone", pos: "名詞", kana: "バッファーゾーン", ja: "緩衝地帯", ex: "A buffer zone was created between the two opposing forces to reduce the risk of accidental clashes.", exJa: "対立する両勢力間に緩衝地帯が設置され、偶発的な衝突のリスクが低減した。", cat: "ニュース", etym: "buffer は古フランス語 bufet（打撃を吸収する）に由来。衝撃を「和らげる」クッションのような役割を持つ地帯", syn: "demilitarized zone（非武装地帯）, neutral strip（中立地帯）, no-man's land（誰のものでもない地域）" },
  { en: "landmine", pos: "名詞", kana: "ランドマイン", ja: "地雷", ex: "Clearance teams worked to remove landmines from the liberated territory before civilians could return.", exJa: "民間人が帰還する前に、解放地域から地雷を除去する作業が進められた。", cat: "ニュース", etym: "land（陸地）+ mine（採掘場・地下の穴）。元々は敵の要塞を破壊するため地下道を掘るmining（坑道掘削）を指したが、19世紀に地面に埋設された爆発装置を意味するように転じた", syn: "IED（即製爆発装置）, explosive device（爆発装置）, ordnance（兵器・弾薬）" },
  { en: "ordinance team", pos: "名詞", kana: "オーディナンスティーム", ja: "兵器処理班", ex: "An ordinance team conducted a controlled explosion to safely destroy the unexploded shells.", exJa: "兵器処理班が不発砲弾を安全に処理するため統制爆破を実施した。", cat: "ニュース", etym: "ordinance はラテン語 ordinantia（命令・規則）に由来し、中世には「統治の条令」を意味したが、後に「大砲・兵器」を指すようになった。不発弾や爆発装置を扱う専門家チーム", syn: "EOD team（爆発物処理班）, disposal unit（廃棄処理班）" },
  { en: "fact-finding", pos: "名詞", kana: "ファクトファインディング", ja: "事実調査", ex: "The UN launched a fact-finding mission to investigate allegations of war crimes in the conflict zone.", exJa: "国連は紛争地域での戦争犯罪疑惑を調査するため事実調査団を派遣した。", cat: "ニュース", etym: "fact はラテン語 factum（行われたこと）に由来。find（発見する）と組み合わせて「真相を明らかにする調査」を意味する複合語", syn: "investigation（調査・捜査）, inquiry（問い合わせ・調査）, assessment（評価・査定）" },
  { en: "observer mission", pos: "名詞", kana: "オブザーバーミッション", ja: "監視団派遣", ex: "International observer missions reported significant violations of the ceasefire agreement by both sides.", exJa: "国際監視団は両勢力による休戦協定の重大な違反を報告した。", cat: "ニュース", etym: "observer はラテン語 observāre（注視する・守る）に由来。mission（使命・派遣）と組み合わせて「第三者による監視的存在」を指す", syn: "monitoring mission（監視任務）, inspection team（視察団）, verification mission（検証団派遣）" },
  { en: "peace envoy", pos: "名詞", kana: "ピースエンボイ", ja: "和平特使", ex: "The newly appointed peace envoy held talks with both warring parties to negotiate a settlement.", exJa: "新任の和平特使は、解決策を交渉するため両交戦勢力と会談した。", cat: "ニュース", etym: "envoy はフランス語 envoyer（送る）に由来。peace（平和）と組み合わせ、紛争解決を目指し派遣される高官を指す", syn: "mediator（仲介者）, negotiator（交渉人）, emissary（使節・特使）" },
  { en: "confidence-building", pos: "名詞", kana: "コンフィデンスビルディング", ja: "信頼醸成", ex: "Confidence-building measures, such as prisoner exchanges, began to ease tensions between the nations.", exJa: "捕虜の交換などの信頼醸成措置により、両国間の緊張が緩和し始めた。", cat: "ニュース", etym: "confidence はラテン語 confidentia（信頼・秘密）に由来。build（構築する）と組み合わせて、対立する当事者間の信頼を段階的に形成する外交的プロセス", syn: "reconciliation（和解・関係修復）, rapprochement（関係改善）, trust-building（信頼構築）" },
  { en: "transit route", pos: "名詞", kana: "トランジットルート", ja: "輸送経路", ex: "Humanitarian organizations requested that the transit route through the border remain open to deliver food supplies.", exJa: "人道支援団体は、食糧供給を届けるため国境経由の輸送経路を開放したままにするよう要請した。", cat: "ニュース", etym: "transit はラテン語 transire（通過する）に由来。route はラテン語 rupta（破られた道）から。援助物資や物資が通過する経路を指す", syn: "supply route（補給路）, corridor（回廊・通路）, passage（通行路）" },
  { en: "supply route", pos: "名詞", kana: "サプライルート", ja: "補給路", ex: "Rebels cut off the main supply route, threatening to starve the besieged city within weeks.", exJa: "反政府勢力が主要補給路を遮断し、包囲された都市が数週間以内に飢饉に陥る危機が生じた。", cat: "ニュース", etym: "supply はラテン語 supplēre（補う）に由来。route と組み合わせて、軍隊や市民への物資供給を支える経路", syn: "transit route（輸送経路）, logistics corridor（物流回廊）, distribution line（配給線）" },
  { en: "aid convoy", pos: "名詞", kana: "エイドコンボイ", ja: "支援車列", ex: "The Red Crescent dispatched an aid convoy carrying medicine and blankets to the displaced population.", exJa: "赤新月社は医薬品と毛布を運ぶ支援車列を、避難民に向けて派遣した。", cat: "ニュース", etym: "aid はラテン語 adjutāre（助ける）に由来。convoy はスペイン語 convoyar（護衛する）から。支援物資を運ぶ複数の車両が隊をなして移動する", syn: "relief convoy（救援車列）, humanitarian mission（人道支援任務）, supply column（補給縦隊）" },
  { en: "host country", pos: "名詞", kana: "ホストカントリー", ja: "受け入れ国", ex: "The host country agreed to provide temporary shelter and medical care for the incoming refugees.", exJa: "受け入れ国は、到着する難民に対して仮設住宅と医療を提供することに同意した。", cat: "ニュース", etym: "host はラテン語 hostis（客・主人）に由来。country（国）と組み合わせて、難民や国際機構を受け入れる側の国家を指す", syn: "receiving nation（受け入れ国）, destination country（到着国）" },
  { en: "receiving center", pos: "名詞", kana: "リシービングセンター", ja: "受け入れ施設", ex: "The newly opened receiving center can accommodate up to 500 displaced persons daily for initial processing.", exJa: "新しくオープンした受け入れ施設は、初期処理のため1日最大500名の避難民を収容できる。", cat: "ニュース", etym: "receive はラテン語 recipere（受け取る）に由来。center（中心・施設）と組み合わせて、難民や避難民が最初に到着する施設を指す", syn: "reception facility（受け入れ施設）, processing center（処理センター）, shelter（避難所）" },
  { en: "screening", pos: "名詞", kana: "スクリーニング", ja: "審査", ex: "All arriving refugees undergo security screening to prevent potential threats from entering the country.", exJa: "到着したすべての難民は、潜在的脅威の国内侵入を防ぐためセキュリティ審査を受ける。", cat: "ニュース", etym: "screen はラテン語 scrinium（箱・容器）に由来し、情報を「ふるい分ける」ことから。難民や入国者の身元・背景を調べる審査プロセス", syn: "vetting（審査・身元確認）, security check（セキュリティチェック）, verification（検証）" },
  { en: "clearance", pos: "名詞", kana: "クリアランス", ja: "許可", ex: "The defense ministry granted clearance for the military aircraft to conduct operations in the designated airspace.", exJa: "国防省は軍用機が指定空域で作戦を展開することの許可を与えた", cat: "ニュース", etym: "ラテン語 clarus（明確・清い）に由来。clear「明確にする」から、障害を取り除いて「許可を与える」という意味に。clear up・clearway と同根", syn: "approval（公式な認可）, authorization（権限委譲）, permission（一般的な許可）" },
  { en: "visa waiver", pos: "名詞", kana: "ビザウェイバー", ja: "査証免除", ex: "Japan and the EU expanded their visa waiver agreement to cover more nationalities starting next year.", exJa: "日本とEUは来年から対象国籍を広げた査証免除協定を拡大した", cat: "ニュース", etym: "visa はラテン語 visus（見られた・視認された）から。waive は古仏語 weyver（見捨てる）由来。査証の提示義務を「見捨てる＝免除する」", syn: "visa-free entry（査証不要の入国）, exemption（免除制度）" },
  { en: "travel advisory", pos: "名詞", kana: "トラベルアドバイザリー", ja: "渡航勧告", ex: "The State Department issued a Level 3 travel advisory for the region following the recent unrest.", exJa: "国務省は最近の混乱を受けてその地域に対し渡航勧告レベル3を発令した", cat: "ニュース", etym: "advisory は advise（助言する）の形容詞形。ラテン語 advisare から。政府が市民に対して旅行の危険性を「助言する」公式声明", syn: "travel warning（渡航警告・より強い警告）, alert（警報・緊急性が高い）" },
  { en: "border crossing", pos: "名詞", kana: "ボーダークロッシング", ja: "国境通過地点", ex: "Humanitarian aid trucks were blocked at the northern border crossing for three days.", exJa: "人道支援のトラックが北部の国境通過地点で3日間足止めされた", cat: "ニュース", etym: "border は古仏語 bordure（縁・端）由来。crossing は cross（横切る）から。国家の「端」を「横切る」場所という地政学的表現", syn: "checkpoint（検問所）, frontier（国境地域・より広い範囲）" },
  { en: "entry point", pos: "名詞", kana: "エントリーポイント", ja: "入国地点", ex: "Customs officials increased security checks at all major entry points following the threat alert.", exJa: "脅迫警報を受けて税関職員はすべての主要入国地点でセキュリティチェックを強化した", cat: "ニュース", etym: "entry は enter（入る）から。point は指す・位置を示す古仏語 pointe 由来。「入国する場所」という機能的な表現", syn: "port of entry（出入港地点・公式用語）, gateway（門戸・比喩的）" },
  { en: "exit permit", pos: "名詞", kana: "エグジットパーミット", ja: "出国許可", ex: "Asylum seekers were denied exit permits and remained stuck in the transit zone.", exJa: "亡命希望者は出国許可を拒否され、通過区域に足止めされたままだ", cat: "ニュース", etym: "exit はラテン語 exire（出て行く）。ex（外へ）+ ire（行く）。permit はラテン語 permittere（許可する）から。出国の許可状を示す法律用語", syn: "departure authorization（出発許可・公式用語）, travel document（旅行書類・広い意味）" },
  { en: "maritime lane", pos: "名詞", kana: "マリタイムレーン", ja: "海上航路", ex: "Tensions escalated after vessels were attacked in one of the world's most critical maritime lanes.", exJa: "世界で最も重要な海上航路の一つで船舶が攻撃された後、緊張が高まった", cat: "ニュース", etym: "maritime はラテン語 mare（海）から。lane は古英語 lane（小道）由来。海の上の「小道＝航路」という比喩的表現。commerce や trade と並ぶ地政学用語", syn: "shipping route（船舶航路）, sea lane（海上航路・ほぼ同義）" },
  { en: "air corridor", pos: "名詞", kana: "エアコリドー", ja: "航空回廊", ex: "A humanitarian air corridor was established to deliver emergency supplies to the besieged city.", exJa: "包囲された都市に緊急物資を輸送するため人道支援の航空回廊が開設された", cat: "ニュース", etym: "air は古仏語 aire（場所）から。corridor はイタリア語 corridore（走者・通路）由来。空の上の「廊下」つまり管制された通路。maritime lane の空版", syn: "flight path（飛行経路・個別）, airway（航空路・同根）" },
  { en: "no-fly area", pos: "名詞", kana: "ノーフライエリア", ja: "飛行禁止区域", ex: "The coalition enforced a no-fly area over the conflict zone to prevent airstrikes on civilian targets.", exJa: "連合軍は紛争地域上空に飛行禁止区域を設定し、民間人への空爆を防いだ", cat: "ニュース", etym: "コアイメージ: no-fly zone の短縮形。area は ラテン語 area（土地・場所）。軍事紛争時に航空機の飛行を「禁止した領域」という冷戦期の造語", syn: "no-fly zone（飛行禁止地帯・ほぼ同義）, restricted airspace（制限空域・より広い）" },
  { en: "joint statement", pos: "名詞", kana: "ジョイントステートメント", ja: "共同声明", ex: "The two leaders signed a joint statement pledging cooperation on climate change and trade.", exJa: "両首脳は気候変動と貿易での協力を約束する共同声明に署名した", cat: "ニュース", etym: "joint はラテン語 iunctus（結合された）。statement は古仏語 statement から。複数の主体が「結合して」発表する公式声明。diplomatic protocol の重要な要素", syn: "communiqué（公式声明・より正式）, press release（プレスリリース・媒体向け）" },
  { en: "press corps", pos: "名詞", kana: "プレスコー", ja: "記者団", ex: "The president held a rare press corps briefing to address concerns about the economic stimulus package.", exJa: "大統領は経済刺激策への懸念に対処するため記者団向けの異例のブリーフィングを開いた", cat: "ニュース", etym: "press はラテン語 pressare（押す）から、活字印刷の「圧力」を経由して「報道機関」へ。corps はラテン語 corpus（身体・集団）。組織化された記者集団を指す正式用語", syn: "media（メディア・広い意味）, journalists（記者・個人を指す）" },
  { en: "photo op", pos: "名詞", kana: "フォトオプ", ja: "写真撮影機会", ex: "Critics argued that the visit was merely a photo op rather than a substantive engagement with local communities.", exJa: "批評家はこの訪問は地域社会との実質的な関わりではなく単なる写真撮影機会だと主張した", cat: "ニュース", etym: "photo は photo + opportunity の短縮スラング。政治家が好意的な印象を与えるための計画された撮影機会。報道論では略語であり、やや軽蔑的なニュアンス含む", syn: "photo opportunity（撮影機会・正式な表現）, picture moment（写真に収める瞬間）" },
  { en: "closed-door session", pos: "名詞", kana: "クローズドドアセッション", ja: "非公開会合", ex: "The committee held a closed-door session to discuss classified intelligence regarding national security threats.", exJa: "委員会は国家安全保障上の脅威に関する機密情報を協議するため非公開会合を開いた", cat: "ニュース", etym: "closed は close（閉じる）から。door は古英語 duru（戸）。session はラテン語 sessio（座ること・会議）。「戸が閉じられた」会議＝報道機関や一般が排除された会合", syn: "private meeting（秘密会議）, off-the-record discussion（オフレコ討議・より非公式）" },
  { en: "draft text", pos: "名詞", kana: "ドラフトテキスト", ja: "草案文書", ex: "Diplomats circulated a draft text of the agreement for member states to review before the summit.", exJa: "外交官はサミット前に加盟国が検討するため協定の草案文書を配布した", cat: "ニュース", etym: "draft は古仏語 drait（引く）から。text はラテン語 textus（織られたもの）。最終版前の「引き出された・仮の文書」という意味。negotiation の中間段階を示す", syn: "preliminary version（初期版）, working document（作業文書・進行中を強調）" },
  { en: "final text", pos: "名詞", kana: "ファイナルテキスト", ja: "最終文書", ex: "After weeks of negotiation, the parties approved the final text of the trade agreement with only minor revisions.", exJa: "数週間の交渉後、各当事者は軽微な修正のみで貿易協定の最終文書を承認した", cat: "ニュース", etym: "final はラテン語 finalis（終わりの）から。text と同じくラテン語 textus。交渉の最終段階で各側が合意した「織り上げられた・完成した文書」", syn: "agreed text（合意文書・交渉後）, official version（公式版・正式性を強調）" },
  { en: "signatory", pos: "名詞", kana: "シグナトリー", ja: "署名国", ex: "The treaty will enter into force once ten signatories have ratified it.", exJa: "条約は10カ国の署名により批准されれば発効する。", cat: "ニュース", etym: "ラテン語 signare（署名する）に由来。sign・signature・designate と同根で、「署名した者・国」を意味する。国際条約の文脈では必ず登場する用語", syn: "party to（条約の当事者・より法的）, participant（参加者・より広義）" },
  { en: "depositary", pos: "名詞", kana: "デポジタリー", ja: "寄託者", ex: "The United Nations is designated as the depositary for the Convention on Biological Diversity.", exJa: "国連は生物多様性条約の寄託国として指定されている。", cat: "ニュース", etym: "ラテン語 depositum（預けられたもの）+ -ary（人・機関）。depository（保管庫）と語源を同じくし、国際条約では「寄託国」として信頼できる第三者機関を指す", syn: "custodian（管理者・より広義）, trustee（受託者・信託関係）" },
  { en: "compliance review", pos: "名詞", kana: "コンプライアンスレビュー", ja: "履行審査", ex: "The committee will conduct a compliance review of all member states' environmental reports.", exJa: "委員会は全加盟国の環境報告書の履行審査を実施する予定だ。", cat: "ニュース", etym: "comply（従う）+ review（検査）。comply は ラテン語 complere（完成させる）に由来し、条約義務の遵守状況を評価する公式プロセス", syn: "verification（検証・より技術的）, assessment（評価・より広義）" },
  { en: "verification team", pos: "名詞", kana: "ベリフィケーションティーム", ja: "検証チーム", ex: "The UN deployed a verification team to assess compliance with the weapons treaty.", exJa: "国連は武器条約の遵守状況を評価するため検証チームを派遣した。", cat: "ニュース", etym: "ラテン語 verus（真実）+ facere（作る）→ verify。事実上の検証・検査を行う専門家チームを指す国際機関用語", syn: "inspection team（査察チーム・より強制的）, audit team（監査チーム・より財務的）" },
  { en: "monitoring mission", pos: "名詞", kana: "モニタリングミッション", ja: "監視任務", ex: "The OSCE launched a long-term monitoring mission to oversee the ceasefire agreement.", exJa: "OSCEは停戦協定を監視するため長期監視任務を開始した。", cat: "ニュース", etym: "ラテン語 monere（警告する）→ monitor。継続的に状況を見守り、異常を検出する国際的な監視活動", syn: "observation mission（観察任務・より中立的）, inspection mission（査察任務・より公式）" },
  { en: "field office", pos: "名詞", kana: "フィールドオフィス", ja: "現地事務所", ex: "The humanitarian organization opened field offices in three border regions to coordinate relief efforts.", exJa: "人道支援機関は3つの国境地域に現地事務所を開設し救援活動を調整している。", cat: "ニュース", etym: "field（実際の土地・現場）+ office。本部ではなく紛争地域・対象地域に直接設置される実行機関", syn: "local office（地域事務所・より一般的）, regional headquarters（地域本部・より大規模）" },
  { en: "liaison office", pos: "名詞", kana: "リエゾンオフィス", ja: "連絡事務所", ex: "The Chinese government established a liaison office in Hong Kong to maintain communication with local authorities.", exJa: "中国政府は地元当局との連絡を維持するため香港に連絡事務所を設置した。", cat: "ニュース", etym: "フランス語 liaison（結び付き）。複数の組織・政府間の情報伝達と調整を担当する小規模な連絡拠点", syn: "representative office（代表事務所・より正式）, contact office（連絡窓口・より非公式）" },
  { en: "policy brief", pos: "名詞", kana: "ポリシーブリーフ", ja: "政策要約", ex: "The think tank released a policy brief recommending stricter regulations on carbon emissions.", exJa: "シンクタンクは炭素排出規制の強化を勧告する政策要約を発表した。", cat: "ニュース", etym: "policy（政策）+ brief（短い・要約版）。政策決定者向けの短くまとめた報告書・提言文書", syn: "executive summary（エグゼクティブサマリー・より企業的）, fact sheet（ファクトシート・より簡潔）" },
  { en: "white paper", pos: "名詞", kana: "ホワイトペーパー", ja: "白書", ex: "The government published a white paper outlining its strategy for digital transformation over the next decade.", exJa: "政府は今後10年間のデジタル変革戦略を示す白書を発表した。", cat: "ニュース", etym: "17世紀の英国で政府発表文書を白い表紙で製本したことに由来。公式見解・政策方針を説明する権威ある文書", syn: "position paper（立場声明・より主張的）, report（報告書・より広義）" },
  { en: "special session", pos: "名詞", kana: "スペシャルセッション", ja: "特別会期", ex: "The UN General Assembly convened a special session to address the humanitarian crisis.", exJa: "国連総会は人道危機に対応するため特別会期を招集した。", cat: "ニュース", etym: "special（特別な）+ session（会期・開催）。通常の会期ではなく緊急・重要案件のため臨時に召集される会合", syn: "emergency session（緊急会期・より切迫感）, extraordinary meeting（臨時会議・より広義）" },
  { en: "floor vote", pos: "名詞", kana: "フロアボート", ja: "本会議採決", ex: "The Senate scheduled a floor vote on the climate bill for next week.", exJa: "上院は気候変動法案の本会議採決を来週予定している。", cat: "ニュース", etym: "floor（議場の床）+ vote。委員会を経た法案・議案が本会議で行われる採決", syn: "plenary vote（本会議投票・より正式）, full assembly vote（全体会議採決・より広義）" },
  { en: "voice vote", pos: "名詞", kana: "ボイスボート", ja: "声による採決", ex: "The committee used a voice vote to pass the procedural motion without formal tallying.", exJa: "委員会は手続き動議を正式な計数なしに声による採決で可決した。", cat: "ニュース", etym: "voice（声・投票）+ vote。議長が賛成・反対の声の大きさで判定する簡略的な採決方式", syn: "verbal vote（口頭投票・より中立）, acclamation（異議なしの採決・より簡略）" },
  { en: "roll call", pos: "名詞", kana: "ロールコール", ja: "記名投票", ex: "The House demanded a roll call vote to ensure transparency on the controversial spending bill.", exJa: "下院は物議を醸す予算法案の透明性を確保するため記名投票を要求した。", cat: "ニュース", etym: "roll（名簿）+ call（呼び上げ）。議員一人ひとりの名前を呼び上げて投票意思を記録する方式", syn: "recorded vote（記録投票・より正式）, name vote（名前による投票・より一般的）" },
  { en: "committee hearing", pos: "名詞", kana: "コミッティーヒアリング", ja: "委員会公聴会", ex: "The Senate Judiciary Committee held a hearing on judicial ethics before the confirmation vote.", exJa: "上院司法委員会は確認採決前に司法倫理についての公聴会を開催した。", cat: "ニュース", etym: "committee（委員会）+ hearing（公開審理）。委員会が専門家・当事者から直接意見・証言を聞く公開の場", syn: "subcommittee hearing（小委員会公聴会・より限定的）, public testimony session（証言聴取会・より広義）" },
  { en: "public hearing", pos: "名詞", kana: "パブリックヒアリング", ja: "公開ヒアリング", ex: "The environmental agency scheduled a public hearing to gather community feedback on the proposed infrastructure project.", exJa: "環境局は提案インフラプロジェクトについて地域の意見を集めるため公開ヒアリングを予定した。", cat: "ニュース", etym: "public（公開の）+ hearing（聴取・協議）。市民・利害関係者が参加でき、政策や事業計画について意見を述べる公開の協議会", syn: "open forum（公開フォーラム・より非公式）, town hall meeting（タウンホールミーティング・より参加型）" },
  { en: "appointment", pos: "名詞", kana: "アポイントメント", ja: "予約", ex: "I have a dentist appointment at 2 PM tomorrow.", exJa: "明日午後2時に歯医者の予約があります", cat: "生活", etym: "ラテン語 ad（～へ）+ point（指す）→「指定された時点へ」。point は「時間・場所を指定する」の意。appoint と同根", syn: "reservation（席や部屋の予約）, booking（施設やサービスの事前予約）" },
  { en: "reservation", pos: "名詞", kana: "レザベーション", ja: "予約席", ex: "Do you have a reservation under the name Smith?", exJa: "スミス名義で予約を取っていますか？", cat: "生活", etym: "ラテン語 reservare（取っておく・確保する）。reserve は「予約する」の意で、reservation はその名詞形。reserv- は「保つ・守る」の語根", syn: "appointment（医者や面談など時間指定の予約）, booking（航空券やホテルの予約）" },
  { en: "itinerary", pos: "名詞", kana: "アイティナラリー", ja: "旅程", ex: "Our itinerary includes stops in Tokyo, Kyoto, and Osaka.", exJa: "私たちの旅程には、東京、京都、大阪での立ち寄りが含まれています", cat: "生活", etym: "ラテン語 iter（道・旅路）から派生。「歩むべき道順」という意。iterate（反復する）と同根の iter", syn: "schedule（予定表・時間割）, route（経路・道順）" },
  { en: "boarding pass", pos: "名詞", kana: "ボーディングパス", ja: "搭乗券", ex: "Please show your boarding pass at the gate.", exJa: "ゲートで搭乗券を提示してください", cat: "生活", etym: "board（乗る・搭乗する）+ pass（通行券）。board はもともと「板・甲板」で、船や飛行機に「乗る」という意味に拡張", syn: "ticket（航空券・乗車券の総称）, gate pass（搭乗口へのパス）" },
  { en: "platform number", pos: "名詞", kana: "プラットフォームナンバー", ja: "乗り場番号", ex: "The train leaves from platform number 7.", exJa: "電車は7番線から出発します", cat: "生活", etym: "platform は「台・演壇」の意のラテン語planus（平らな）が語源。駅の「プラットフォーム」は乗降する平らな台から", syn: "gate number（空港の搭乗口番号）, track number（駅のホーム番号）" },
  { en: "transfer", pos: "名詞", kana: "トランスファー", ja: "乗り換え", ex: "You need to transfer to the red line at the next station.", exJa: "次の駅で赤線に乗り換える必要があります", cat: "生活", etym: "ラテン語 trans（越えて）+ ferre（運ぶ）→「向こう側へ運ぶ・移す」。transport・transform と同根の trans + fer", syn: "connection（接続便・乗り継ぎ）, change（乗り換え・英国寄り）" },
  { en: "commute", pos: "名詞", kana: "コミュート", ja: "通勤", ex: "My daily commute takes about an hour.", exJa: "毎日の通勤に約1時間かかります", cat: "生活", etym: "ラテン語 com（一緒に）+ mutare（変える・交換する）→「往復する」の意。commute ticket は往復乗車券", syn: "travel to work（仕事に向かう移動）, daily journey（日々の移動一般）" },
  { en: "detour", pos: "名詞", kana: "ディトゥア", ja: "迂回路", ex: "Road construction forced us to take a detour.", exJa: "道路工事のため迂回を余儀なくされました", cat: "生活", etym: "フランス語 détour。ラテン語 de（から）+ tornus（回す）→「回り道をする」。tour と同根", syn: "bypass（迂回路・道路）, alternative route（別経路）" },
  { en: "intersection", pos: "名詞", kana: "インターセクション", ja: "交差点", ex: "Turn right at the next intersection.", exJa: "次の交差点を右に曲がってください", cat: "生活", etym: "ラテン語 inter（間に）+ secare（切る）→「相互に切り交わる」。intersect（交差する）と同根", syn: "crossroads（十字路・分岐点）, junction（接合部・合流地点）" },
  { en: "crosswalk", pos: "名詞", kana: "クロスウォーク", ja: "横断歩道", ex: "Please use the crosswalk to cross the street safely.", exJa: "横断歩道を使って安全に道を渡ってください", cat: "生活", etym: "cross（横切る）+ walk（歩く）の複合語。cross は「十字型に交わる」の意のラテン語 crux が語源", syn: "zebra crossing（横断歩道・英国寄り）, pedestrian crossing（歩行者横断路）" },
  { en: "fare", pos: "名詞", kana: "フェア", ja: "運賃", ex: "The bus fare has increased by 10% this month.", exJa: "今月のバス運賃が10%値上がりしました", cat: "生活", etym: "古英語 fær（旅・移動）が語源。食べ物も fare と呼ぶ理由は、旅人の「食事・供給」という意味から派生", syn: "fee（使用料・手数料）, charge（料金・請求額）" },
  { en: "refund", pos: "名詞", kana: "リファンド", ja: "払い戻し", ex: "If you cancel within 24 hours, you'll receive a full refund.", exJa: "24時間以内にキャンセルすれば、全額払い戻しが受けられます", cat: "生活", etym: "ラテン語 re（戻す）+ fundere（注ぐ・返す）→「お金を返す」。fund も同根で語義は「資金」", syn: "reimbursement（払い戻し・補償）, return（返金・返品）" },
  { en: "receipt", pos: "名詞", kana: "レシート", ja: "領収書", ex: "Keep your receipt in case you need to return the item.", exJa: "返品する場合に備えて、領収書を保管してください", cat: "生活", etym: "ラテン語 receptus（受け取った）から。receive（受け取る）と同根。receipt は「受け取りの証拠」", syn: "proof of purchase（購入証明）, invoice（請求書・正式な書類）" },
  { en: "invoice", pos: "名詞", kana: "インボイス", ja: "請求書", ex: "The invoice shows the total amount due by the end of the month.", exJa: "請求書には月末までの支払期限が記載されています", cat: "生活", etym: "フランス語 envois（送付品）が語源。「送付される品目リスト」から「請求書」の意に。invoiced goods は「請求対象の商品」", syn: "bill（請求額・明細書）, statement（請求明細・銀行残高報告書）" },
  { en: "quotation", pos: "名詞", kana: "クオーテーション", ja: "見積書", ex: "We requested a quotation from three different contractors.", exJa: "3社の異なる業者から見積書を取り寄せました", cat: "生活", etym: "ラテン語 quotus（どの程度の）+ -ation。quote は「値段を述べる」の意で、quotation は「提示された見積もり」", syn: "estimate（見積もり・推定額）, proposal（提案書・提示額）" },
  { en: "deadline", pos: "名詞", kana: "デッドライン", ja: "締め切り", ex: "The project deadline is Friday, so we need to submit the report by 5 PM.", exJa: "プロジェクトの締め切りは金曜日なので、午後5時までにレポートを提出する必要があります。", cat: "生活", etym: "コアイメージ: dead（死）+ line（線）→ その線を越えたら終わり、もう取り返しがつかない。時間の死線。", syn: "due date（納期・期限一般）, time limit（厳密な時間制限）, cutoff（最終期限・これ以上は受け付けない感）" },
  { en: "extension", pos: "名詞", kana: "エクステンション", ja: "延長", ex: "Can you request an extension on the deadline? I need another week to finish.", exJa: "締め切りの延長を申請できますか？あと1週間必要です。", cat: "生活", etym: "ラテン語 extendere（伸ばす）→ extend＝期限や期間を時間軸上に伸ばす。expand・extend は同根だが、期限には extension を使う。", syn: "postponement（延期・日時をずらす）, delay（遅延・予定より後ろ倒し）, prolongation（期間を長くする・フォーマル）" },
  { en: "approval form", pos: "名詞", kana: "アプルーバルフォーム", ja: "承認書", ex: "Please fill out the approval form and send it to the manager by tomorrow.", exJa: "承認書に記入して、明日までにマネージャーに送ってください。", cat: "生活", etym: "approve＝ラテン語 approbāre（同意する）。form（フォーム・用紙）と合わせて、公式な同意を示す書類。", syn: "authorization document（公式な許可書）, sign-off sheet（了承シート）" },
  { en: "signature", pos: "名詞", kana: "シグネチャー", ja: "署名", ex: "All three directors need to put their signature on the contract.", exJa: "3人の取締役全員が契約書に署名する必要があります。", cat: "生活", etym: "ラテン語 signāre（標識をつける・署名する）。sign（記号・兆候）と同根。署名は個人を証明する一種の記号。", syn: "sign-off（了承の署名）, endorsement（裏書き・支持の署名）, countersignature（副署）" },
  { en: "initials", pos: "名詞", kana: "イニシャルズ", ja: "頭文字署名", ex: "Just put your initials here to acknowledge you've read the memo.", exJa: "メモを読んだことを確認するために、ここに頭文字を書いてください。", cat: "生活", etym: "初期の initial＝ラテン語 initium（開始・最初）。姓名の頭文字だけを書く、最も簡潔な「標識」。", syn: "monogram（頭文字を組み合わせた紋章・装飾的）" },
  { en: "memo", pos: "名詞", kana: "メモ", ja: "社内メモ", ex: "I received a memo from HR about the new attendance policy.", exJa: "人事部から新しい出勤ポリシーについてのメモを受け取りました。", cat: "生活", etym: "ラテン語 memorandum（記憶すべきこと）の略形。memo＝覚え書き・記録用の短い書きつけ。", syn: "note（一般的なメモ・手書き可）, memorandum（正式なメモ・フォーマル）" },
  { en: "minutes", pos: "名詞", kana: "ミニッツ", ja: "議事録", ex: "Could you review the meeting minutes and email them to all attendees?", exJa: "会議の議事録をレビューして、すべての出席者にメールで送ってもらえますか？", cat: "生活", etym: "コアイメージ: minute（細かい）→ 会議の細かい内容を記録した書類。時間単位の「分」とは別の語（綴りは同じだが語源が異なる）。", syn: "notes（会議の記録・一般的）, proceedings（議事進行・正式な記録）, transcript（議論の逐語記録）" },
  { en: "agenda item", pos: "名詞", kana: "アジェンダアイテム", ja: "議題項目", ex: "The first agenda item is a review of Q3 sales performance.", exJa: "最初の議題項目は第3四半期の売上実績のレビューです。", cat: "生活", etym: "agenda＝ラテン語 agendum（なされるべきこと）の複数形。会議で扱うべき議論の項目一つ一つ。", syn: "topic（一般的な話題）, discussion point（話し合うポイント）" },
  { en: "conference room", pos: "名詞", kana: "カンファレンスルーム", ja: "会議室", ex: "The conference room is booked for 2 PM, so let's move our discussion there.", exJa: "会議室は午後2時に予約されているので、そこで議論を続けましょう。", cat: "生活", etym: "conference＝ラテン語 conferre（持ち寄る・相談する）。複数人が集まって話し合う部屋。", syn: "meeting room（会議室・一般的）, boardroom（役員会議室・大型・フォーマル）" },
  { en: "workstation", pos: "名詞", kana: "ワークステーション", ja: "作業席", ex: "Each employee has their own workstation with a desk and computer.", exJa: "各従業員には机とコンピュータを備えた個別の作業席があります。", cat: "生活", etym: "コアイメージ: work（仕事）+ station（駅・定位置）→ 従業員が仕事をする指定された場所。オフィス環境での個人の作業スペース。", syn: "desk（机・一般的）, cubicle（パーティション仕切りの個人スペース）" },
  { en: "cafeteria", pos: "名詞", kana: "カフェテリア", ja: "社員食堂", ex: "The company cafeteria offers lunch at a discount for all employees.", exJa: "会社の食堂ではすべての従業員にお弁当をお手頃価格で提供しています。", cat: "生活", etym: "スペイン語 cafetería由来。café（カフェ）+接尾辞 -tería。大勢が食事をするセルフサービス式の食堂。", syn: "canteen（食堂・英国寄り）, break room（休憩室・軽食程度）, dining hall（食堂・大規模施設）" },
  { en: "vendor", pos: "名詞", kana: "ベンダー", ja: "取引先", ex: "We need to negotiate new terms with our vendor before renewing the contract.", exJa: "契約を更新する前に、取引先と新しい条件を交渉する必要があります。", cat: "生活", etym: "ラテン語 vendere（売る）→ 商品やサービスを売る側の業者。vend・vendor・sale と同根。", syn: "supplier（サプライヤー・物資供給）, contractor（契約業者・サービス提供）, partner（パートナー・協力関係）" },
  { en: "client meeting", pos: "名詞", kana: "クライアントミーティング", ja: "顧客打ち合わせ", ex: "A: Do you have any time next week for a client meeting? / B: How about Tuesday afternoon?", exJa: "A: 来週、顧客との打ち合わせの時間がありますか？/ B: 火曜日の午後はどうですか？", cat: "生活", etym: "client＝ラテン語 cliens（保護下にある者）。meeting＝meet（会う）。顧客と会社が対面で話し合う会議。", syn: "customer session（顧客セッション・カジュアル）, business meeting（商談・広い範囲）" },
  { en: "follow-up", pos: "名詞", kana: "フォローアップ", ja: "追跡連絡", ex: "A: I'll send you a follow-up email with the details. / B: Thanks, I appreciate that.", exJa: "A: 詳細を記載した追跡メールを送ります。/ B: ありがとうございます、助かります。", cat: "生活", etym: "コアイメージ: follow（後ろについていく）+ up（上へ）→ 前の会話や約束を後から追いかけて確認する行動。", syn: "check-in（状況確認・カジュアル）, touchbase（接触・進捗確認）" },
  { en: "reminder", pos: "名詞", kana: "リマインダー", ja: "通知", ex: "A: Did you get the calendar reminder for the meeting? / B: Yes, it popped up this morning.", exJa: "A: 会議のカレンダー通知を受け取りましたか？/ B: はい、今朝ポップアップが出ました。", cat: "生活", etym: "remind＝ラテン語 re（再び）+ mindāre（心に留める）→ もう一度心に留めさせるもの。", syn: "notification（通知・システム的）, alert（警告・緊急性が高い）, notice（告知・公式）" },
  { en: "schedule", pos: "名詞", kana: "スケジュール", ja: "予定", ex: "The meeting is scheduled for next Tuesday at 2 PM.", exJa: "その会議は来週火曜日の午後2時に予定されています", cat: "生活", etym: "ラテン語 schedula（小さな紙片）に由来。元々は「紙」を意味し、そこに予定を記す習慣から「予定表」の意味に。scheme・schematic と同根", syn: "timetable（時間割・時刻表・英国寄り）, itinerary（行程表・旅行用）, agenda（会議予定・公式な議題）" },
  { en: "calendar", pos: "名詞", kana: "カレンダー", ja: "予定表", ex: "I use my phone calendar to keep track of all my appointments.", exJa: "すべての予定を追跡するためにスマートフォンのカレンダーを使っています", cat: "生活", etym: "ラテン語 calendae（月の第1日）に由来。古代ローマで月初めに債務者が返済期限を記録したことから。calorie も同じ語根 cal-（熱）を持つ関連語", syn: "planner（計画表・手帳）, schedule（予定・広義）, almanac（暦・年鑑）" },
  { en: "postponement", pos: "名詞", kana: "ポストポーンメント", ja: "延期", ex: "The postponement of the event was announced due to bad weather.", exJa: "悪天候のため、イベントの延期が発表されました", cat: "生活", etym: "ラテン語 postponere（後ろに置く）= post（後ろ）+ ponere（置く）。反対語は antecede（先行する）。postpone・postponed がよく使われる動詞形", syn: "delay（遅延・より広義）, adjournment（会議の延期・公式）, deferral（先送り・やや堅い）" },
  { en: "cancellation", pos: "名詞", kana: "キャンセレーション", ja: "取り消し", ex: "The airline issued a full refund following the flight cancellation.", exJa: "航空会社はフライト取り消し後、全額払い戻しを発行しました", cat: "生活", etym: "ラテン語 cancellare（格子で消す）に由来。文書の文字を格子線で塗りつぶす習慣から。cancel・cancelled が基動詞", syn: "abolition（廃止・制度的）, withdrawal（取り下げ）, termination（終了・契約解除）" },
  { en: "attendance", pos: "名詞", kana: "アテンダンス", ja: "出席", ex: "Perfect attendance was rewarded with a certificate at the company meeting.", exJa: "完全出席は会社の会議で証書で報酬されました", cat: "生活", etym: "ラテン語 attendere（~に注意を向ける）= ad（～へ）+ tendere（伸ばす）。「その場に居て注意を払う」から「出席」に。attend・attentive と同根", syn: "presence（存在・在席）, participation（参加・関与度が高い）, turnout（参加者数）" },
  { en: "absence", pos: "名詞", kana: "アブセンス", ja: "欠席", ex: "His absence from the project meeting raised concerns among the team members.", exJa: "プロジェクト会議への彼の欠席はチームメンバーの間で懸念を招きました", cat: "生活", etym: "ラテン語 abesse（いない）= ab（離れて）+ esse（いる）。present（出席）の対義語で、もともと「そこにいない状態」の意味。absent・absenteeism と同根", syn: "nonattendance（不出席・堅い）, truancy（ずる休み・学生向け）, leave（休暇・許可取得）" },
  { en: "overtime", pos: "名詞", kana: "オーバータイム", ja: "残業", ex: "Employees are entitled to overtime pay at 1.5 times their regular hourly rate.", exJa: "従業員は通常時給の1.5倍の残業手当を受け取る権利があります", cat: "生活", etym: "コアイメージ: over（超えて）+ time（時間）→ 定時を超えた時間労働。日本語の「残業」より時間超過のニュアンスが強い。overtime pay は給与項目として重要", syn: "extra hours（追加勤務・一般的）, overwork（過労・ネガティブ）, extension（時間延長）" },
  { en: "shift", pos: "名詞", kana: "シフト", ja: "勤務帯", ex: "I have to work the night shift next week, so my sleep schedule will be completely different.", exJa: "来週は夜勤シフトなので、睡眠スケジュールが完全に変わります", cat: "生活", etym: "中英語 shiften（変わる・移動する）に由来。勤務者が交代する＝「シフト交代」。日本語でも「シフト」として借用語化。shift key（キーボード）とも無関係ではない動き", syn: "rotation（交代・循環）, stint（一定期間の勤務）, tour（勤務期間）" },
  { en: "payroll", pos: "名詞", kana: "ペイロール", ja: "給与台帳", ex: "The company's payroll department processes all employee salaries and benefits.", exJa: "会社の給与部門はすべての従業員の給与と福利厚生を処理します", cat: "生活", etym: "コアイメージ: pay（給与）+ roll（名簿・台帳）→ 給与支給対象者の記録。企業の給与管理システムを指すことが多い。payroll department は人事部門の重要な部分", syn: "salary list（給与一覧）, wage roll（賃金台帳）, employee roster（従業員名簿）" },
  { en: "allowance", pos: "名詞", kana: "アローワンス", ja: "手当", ex: "The government increased the cost-of-living allowance for public sector employees.", exJa: "政府は公務員の生活手当を引き上げました", cat: "生活", etym: "ラテン語 allaudare（承認する）= al（~へ）+ laudare（褒める）から。子どもの小遣いから役員手当まで、「認められた追加支給」という文脈。allot（割り当てる）と同根", syn: "stipend（定期的支給・給付）, subsidy（補助金・公的）, benefit（福利厚生・広義）" },
  { en: "bonus", pos: "名詞", kana: "ボーナス", ja: "賞与", ex: "Employees received a generous year-end bonus due to the company's strong performance.", exJa: "会社の好調な業績のため、従業員は手厚い年末賞与を受け取りました", cat: "生活", etym: "ラテン語 bonus（良い）に由来。元々『ラテン語辞書』で「良いもの」の例として登場。現代では業績報酬の代名詞。bonus track（隠しトラック）でも使用される", syn: "incentive（奨励金・成果連動）, premium（上乗せ）, gratuity（退職金・恩恵的）" },
  { en: "deduction", pos: "名詞", kana: "ディダクション", ja: "控除", ex: "Tax deductions reduce your taxable income and lower the amount of tax you owe.", exJa: "税控除は課税所得を減らし、納める税金の額を低くします", cat: "生活", etym: "ラテン語 deducere（引き下ろす）= de（下へ）+ ducere（導く）。給与から税金などを「引く」という物理的なイメージ。deduce（推論する）と同根だが、そちらは論理的な「引く」", syn: "withholding（差し引き・税務用）, reduction（削減）, subtraction（減額）" },
  { en: "reimbursement", pos: "名詞", kana: "リインバースメント", ja: "経費精算", ex: "Submit your expense receipts within 30 days to request reimbursement.", exJa: "返金をリクエストするために、経費領収書を30日以内に提出してください", cat: "生活", etym: "フランス語 rembourser（返金する）= re（再び）+ bourse（財布）。出張などで立て替えた経費を「財布に戻す」という発想。reimburse の名詞形", syn: "refund（返金・一般的）, repayment（返済）, compensation（補償・損害賠償的）" },
  { en: "expense", pos: "名詞", kana: "エクスペンス", ja: "経費", ex: "All business expenses must be documented with receipts for accounting purposes.", exJa: "すべての事業経費は会計目的で領収書で証明される必要があります", cat: "生活", etym: "ラテン語 expendere（支出する）= ex（外へ）+ pendere（掛ける）。お金が「外に出て行く」というイメージから。expend・expensive と同根。expense report は出張経費報告書", syn: "cost（費用・一般的）, expenditure（支出・堅い）, outlay（出費・投資的）" },
  { en: "stationery", pos: "名詞", kana: "ステーショナリー", ja: "文房具", ex: "The office manager ordered new stationery supplies including pens, paper, and folders.", exJa: "オフィスマネージャーはペン、紙、フォルダを含む新しい文房具を注文しました", cat: "生活", etym: "ラテン語 stationarius（定住する人）に由来。中世で、書類用紙や筆記用具を販売する「定店の商人」を指した。stationary（固定した）と綴りが異なることに注意", syn: "supplies（消耗品・広義）, paper goods（紙製品・限定的）, office equipment（オフィス用品）" },
  { en: "printer", pos: "名詞", kana: "プリンター", ja: "印刷機", ex: "The printer in the office keeps jamming, so we need to call a technician.", exJa: "オフィスのプリンターがよく詰まるので、技術者に連絡する必要があります", cat: "生活", etym: "動詞 print（印刷する）+ -er（道具）。print は中世ラテン語 premere（押す）から、活字を紙に押し付ける行為に由来", syn: "inkjet printer（インクジェット式・家庭向け）, laser printer（レーザー式・高速・業務向け）, multifunction printer（複合機・印刷+スキャン機能）" },
  { en: "photocopier", pos: "名詞", kana: "フォトコピア", ja: "コピー機", ex: "I need to make 50 copies, but the photocopier is broken again.", exJa: "50部コピーが必要ですが、またコピー機が壊れています", cat: "生活", etym: "photo-（光）+ copier（複製機）。ギリシャ語 photo-（光）と copy（複製）が 1950年代に組み合わさり、光学式複写技術の登場とともに造語された", syn: "copier（短縮形・日常会話向け）, copy machine（米国式・より正式）, duplicator（複写機・やや古い表現）" },
  { en: "badge", pos: "名詞", kana: "バッジ", ja: "社員証", ex: "Don't forget your badge before entering the building.", exJa: "建物に入る前にバッジを忘れずに", cat: "生活", etym: "語源は不確か。14世紀の heraldry（紋章学）に遡り、身につける標識・徽章を意味した。identification badge の形式で職場での識別に定着", syn: "ID card（身分証明書・総称）, access card（アクセスカード・建物出入用）, security pass（セキュリティパス・より公式）" },
  { en: "password reset", pos: "名詞", kana: "パスワードリセット", ja: "パスワード再設定", ex: "If you can't remember your password, click on 'password reset' and check your email.", exJa: "パスワードを忘れた場合は、『パスワード再設定』をクリックしてメールを確認してください", cat: "生活", etym: "password は中世フランス語 passe（通す）+ word。reset は re-（再び）+ set（設定する）。デジタル時代に確立した複合表現", syn: "change password（パスワード変更・単純な更新）, reset credentials（認証情報リセット・より技術的）" },
  { en: "login", pos: "名詞", kana: "ログイン", ja: "ログイン", ex: "You'll need to login to access your account on the company portal.", exJa: "社内ポータルのアカウントにアクセスするにはログインが必要です", cat: "生活", etym: "log-in は log（記録）+ in（入る）。19世紀の航海日誌 logbook が語源で、1960年代のコンピュータ用語で『システムへの入場記録』の意で採用された", syn: "sign in（ログイン・やや日常的）, log on（ログオン・主にWindows系）, authenticate（認証する・より技術的）" },
  { en: "logout", pos: "名詞", kana: "ログアウト", ja: "ログアウト", ex: "Always remember to logout when you leave your desk for security reasons.", exJa: "セキュリティのため、机を離れるときは必ずログアウトしてください", cat: "生活", etym: "login の逆操作として 1960年代に formation された。log out は『記録を終了して出る』という意。logout と一語化", syn: "sign out（ログアウト・やや日常的）, log off（ログオフ・主にWindows系）" },
  { en: "attachment", pos: "名詞", kana: "アタッチメント", ja: "添付ファイル", ex: "Please send me the document as an attachment rather than pasting it in the email body.", exJa: "メール本文に貼り付けるのではなく、添付ファイルとして送ってください", cat: "生活", etym: "attach（付ける）+ -ment（名詞化）。ラテン語 attaccare（くっつける）に遡る。email attachment は 1990年代インターネット普及期に定着", syn: "file（ファイル・一般的）, enclosure（同封物・やや正式）, annexed file（添付ファイル・より技術的）" },
  { en: "spreadsheet", pos: "名詞", kana: "スプレッドシート", ja: "表計算ファイル", ex: "I'll analyze the sales data using a spreadsheet to create charts.", exJa: "グラフを作成するために、スプレッドシートを使って売上データを分析します", cat: "生活", etym: "spread（広げる）+ sheet（紙）。会計士が手書きで行列状に広げた計算用紙の呼び方が語源。1979年の VisiCalc で電子化", syn: "Excel file（エクセルファイル・具体的製品名）, worksheet（ワークシート・シート単位での呼び方）, data table（データ表・より一般的）" },
  { en: "presentation", pos: "名詞", kana: "プレゼンテーション", ja: "発表資料", ex: "My presentation on Q3 results is scheduled for next Friday.", exJa: "Q3 の成績に関する発表資料は来週の金曜日に予定されています", cat: "生活", etym: "present（提示する）+ -ation（名詞化）。ラテン語 praesentare（目の前に置く）。PowerPoint 時代に資料と発表の両意で多用", syn: "slideshow（スライドショー・スライド群）, deck（デッキ・スライド資料の俗語）, pitch（ピッチ・プレゼンテーション行為を指す）" },
  { en: "handout", pos: "名詞", kana: "ハンドアウト", ja: "配布資料", ex: "The speaker distributed a handout summarizing the key points of the presentation.", exJa: "講演者は発表の要点をまとめた配布資料を配りました", cat: "生活", etym: "hand out（手で配る）。hand（手）+ out（外に）。元は『配布される物』を指す。講義やセミナーの配布資料として定着", syn: "pamphlet（パンフレット・より装飾的・厚め）, leaflet（リーフレット・薄い配布物）, brochure（ブロシュア・観光情報など）" },
  { en: "checklist", pos: "名詞", kana: "チェックリスト", ja: "確認表", ex: "Before launching the product, go through this quality checklist with your team.", exJa: "製品を発売する前に、このチェックリストをチームで確認してください", cat: "生活", etym: "check（確認する）+ list（一覧）。check は古フランス語 chec（国王将棋で『王手』）。aviation や medical safety で普及した職業用語", syn: "to-do list（やることリスト・個人の行動管理）, task list（タスクリスト・より広い作業管理）, inventory（インベントリ・在庫リスト）" },
  { en: "laundry", pos: "名詞", kana: "ランドリー", ja: "洗濯", ex: "I need to do laundry this weekend because I'm running out of clean clothes.", exJa: "きれいな洋服がなくなってきたので、週末に洗濯する必要があります", cat: "生活", etym: "古フランス語 lavanderia（洗う場所）に遡る。ラテン語 lavare（洗う）+ -ry（場所・行為）。中世から洗濯業の意で使用", syn: "washing（洗浄・より一般的）, dry cleaning（ドライクリーニング・化学薬品使用）, hand wash（手洗い・デリケート素材向け）" },
  { en: "detergent", pos: "名詞", kana: "ディタージェント", ja: "洗剤", ex: "This laundry detergent removes tough stains better than traditional soap.", exJa: "この洗剤は従来の石鹸より頑固な汚れを落とします", cat: "生活", etym: "ラテン語 detergere（拭き去る）。de-（除去）+ tergere（拭く）。1900年代の化学工業発展で、石鹸に代わる合成洗剤として命名", syn: "soap（石けん・より自然派・温和）, cleaner（クリーナー・広い用途・多目的）, washing powder（洗濯粉・粉末タイプ・英国寄り）" },
  { en: "dishwasher", pos: "名詞", kana: "ディッシュウォッシャー", ja: "食洗機", ex: "Just load the dishes in the dishwasher and press the start button.", exJa: "お皿を食洗機に入れてスタートボタンを押すだけです", cat: "生活", etym: "dish（皿）+ washer（洗う機械）。dish は古英語 disc（円盤）から。1950年代の家電革命で一般家庭に普及した造語", syn: "automatic dishwasher（自動食洗機・正式名）, dish machine（ディッシュマシン・より簡潔）" },
  { en: "microwave", pos: "名詞", kana: "マイクロウェーブ", ja: "電子レンジ", ex: "I'll heat up the leftovers in the microwave for two minutes.", exJa: "残った料理を電子レンジで 2 分温めます", cat: "生活", etym: "micro-（小さい）+ wave（波）。1945年にレーダー技術から派生し、マイクロ波による加熱原理を語源とする。1970年代に家庭普及", syn: "microwave oven（マイクロウェーブオーブン・正式名）, MW（エムダブリュー・略語）, nuker（ヌーカー・俗語・米国）" },
  { en: "freezer", pos: "名詞", kana: "フリーザー", ja: "冷凍庫", ex: "A: Where should I put the ice cream? / B: Just toss it in the freezer.", exJa: "A: アイスクリームどこに入れたらいい？/ B: 冷凍庫にぽいっと入れちゃえば", cat: "生活", etym: "コアイメージ: freeze（凍らせる）+ -er（もの・装置）→ 物を凍らせる機械。refrigerator と並ぶ冷蔵関連の重要語", syn: "refrigerator（冷蔵庫・冷凍機能付き）, ice box（アイスボックス・昔の保冷庫）" },
  { en: "pantry", pos: "名詞", kana: "パントリー", ja: "食品庫", ex: "A: Do we have any flour left? / B: Check the pantry—I think there's some on the shelf.", exJa: "A: 小麦粉ある？/ B: 食品庫を見てみて、棚にあったと思うよ", cat: "生活", etym: "ラテン語 panis（パン）→ パンや食料を保管する部屋。中世から使われた歴史ある単語で、brittle pantry（パン食糧庫）と呼ばれた", syn: "larder（食品貯蔵室・英国寄り）, cupboard（食器棚・食品棚兼用）" },
  { en: "groceries", pos: "名詞", kana: "グロサリーズ", ja: "食料品", ex: "A: I'm heading to the store. Need anything? / B: Yeah, could you grab some groceries? We're running low.", exJa: "A: 店に行くけど、何か必要？/ B: そうだね、食料品を買ってきてくれない？足りなくなってるんだ", cat: "生活", etym: "フランス語 grocer（食料雑貨商）← gross（大量）。一般食料品すべてを指す日常語で、複数形 groceries が標準", syn: "provisions（食糧・やや格式的）, supplies（生活用品・広い範囲）" },
  { en: "shopping cart", pos: "名詞", kana: "ショッピングカート", ja: "買い物かご", ex: "A: This shopping cart's wheel is broken. / B: Grab another one from over there.", exJa: "A: このカート、車輪が壊れてる/ B: あそこから別のを持ってきて", cat: "生活", etym: "コアイメージ: cart（荷車）→ スーパーで商品を運ぶ車輪付き容器。米英では「cart」、英国では「trolley」と呼び分けられる", syn: "basket（買い物かご・小型）, trolley（買い物かご・英国寄り）" },
  { en: "checkout", pos: "名詞", kana: "チェックアウト", ja: "会計", ex: "A: The checkout line is so long today. / B: Yeah, let's come back later.", exJa: "A: 今日レジ列がすごく長いね/ B: そだね、後で来よう", cat: "生活", etym: "コアイメージ: check（確認）+ out（出て行く）→ 商品確認して代金を払い出て行く。現代的な複合語で動詞・名詞どちらでも使える", syn: "register（レジ・機械自体）, till（レジボックス・英国寄り）" },
  { en: "cashier", pos: "名詞", kana: "キャッシャー", ja: "レジ係", ex: "A: Is there a self-checkout, or do I need to talk to a cashier? / B: You can use the self-checkout over there.", exJa: "A: セルフレジある？それともレジ係さんに対応してもらう？/ B: あっちのセルフレジ使ってもいいよ", cat: "生活", etym: "フランス語 caisse（現金箱）← ラテン語 capsa（箱）。cash と同根で、金銭を扱う人の専門職を指す", syn: "teller（銀行窓口係・銀行業務）, clerk（店員・一般的）" },
  { en: "discount", pos: "名詞", kana: "ディスカウント", ja: "割引", ex: "A: Do you have a discount code? / B: Try this one—it should save you 20%.", exJa: "A: 割引コードある？/ B: これ試してみて、20%安くなるはずだよ", cat: "生活", etym: "ラテン語 dis-（下へ）+ computare（計算）→ 定価から差し引く。銀行用語の「割引手形」から一般的な値引きまで広く使われる", syn: "reduction（値引き・やや格式的）, sale（セール・期間限定）" },
  { en: "coupon", pos: "名詞", kana: "クーポン", ja: "割引券", ex: "A: I found a coupon for 50% off. / B: Nice! Where did you see it?", exJa: "A: 50%オフのクーポン見つけた/ B: いいね！どこで見つけたの？", cat: "生活", etym: "フランス語 coupon（切り取り）← couper（切る）。もともと証券や切り手の意味で、今は割引・無料配布の券全般を指す", syn: "voucher（商品券・広い用途）, ticket（チケット・割引券兼用）" },
  { en: "loyalty card", pos: "名詞", kana: "ロイヤルティカード", ja: "ポイントカード", ex: "A: Don't forget to swipe your loyalty card at checkout. / B: Oh, good catch! I almost left without it.", exJa: "A: 会計の時にポイントカード忘れずにね/ B: あ、ありがとう！そのまま出るとこだった", cat: "生活", etym: "コアイメージ: loyalty（忠誠・継続購買）→ 常連客の継続購買を報酬で支援する仕組み。customer card・rewards card とも呼ばれる", syn: "rewards card（リワードカード・ポイント還元型）, membership card（会員カード）" },
  { en: "warranty", pos: "名詞", kana: "ワランティ", ja: "保証", ex: "A: Does this laptop come with a warranty? / B: Yes, it's covered for two years.", exJa: "A: このノートパソコン保証つき？/ B: そう、2年間保証がついてる", cat: "生活", etym: "フランス語 garantie（保証）← ゲルマン語 wara-（注意深い）。法的責任を伴う商品保証の専門用語で、guarantee より正式", syn: "guarantee（保証・法的拘束力）, assurance（保証・安心感重視）" },
  { en: "exchange", pos: "名詞", kana: "エクスチェンジ", ja: "交換", ex: "A: This shirt doesn't fit. Can I exchange it? / B: Sure, just bring it back with the receipt.", exJa: "A: このシャツサイズ合わないんですけど、交換できます？/ B: もちろん。レシートを持って来てください", cat: "生活", etym: "ラテン語 ex-（外へ）+ change（変える）→ 物と物を入れ替える。取引・両替など広く使われるが、返品時は「return と exchange」で区別される", syn: "swap（入れ替え・カジュアル）, replacement（代替品・正式）" },
  { en: "customer desk", pos: "名詞", kana: "カスタマーデスク", ja: "案内窓口", ex: "A: Where can I find the customer desk? / B: It's at the front of the store, near the main entrance.", exJa: "A: 案内窓口ってどこ？/ B: 店の前、正面入口の近くだよ", cat: "生活", etym: "コアイメージ: desk（机・窓口）+ customer（顧客）→ 顧客対応の拠点。information desk・service desk とも言い、店舗最大の接客ポイント", syn: "information desk（インフォメーションデスク）, service counter（サービスカウンター）" },
  { en: "fitting room", pos: "名詞", kana: "フィッティングルーム", ja: "試着室", ex: "A: Can I try this on? Where's the fitting room? / B: Down that aisle on the left.", exJa: "A: これ試着したいんですけど、試着室どこですか？/ B: あの通路を左に行ったとこです", cat: "生活", etym: "コアイメージ: fit（合う・試着）+ room（部屋）→ 衣服が体に合うか確認する個室。changing room・dressing room とも呼ばれる", syn: "changing room（着替え室・英国寄り）, dressing room（ドレッシングルーム）" },
  { en: "size chart", pos: "名詞", kana: "サイズチャート", ja: "サイズ表", ex: "A: What's your usual size? / B: I'm not sure—let me check the size chart to see S or M fits better.", exJa: "A: いつもサイズいくつなの？/ B: よくわかんないから、サイズ表で S か M どっちか確認しようかな", cat: "生活", etym: "コアイメージ: chart（表・図表）+ size（サイズ）→ 衣服・靴の国別サイズ対応表。オンライン購入の際に不可欠な情報ツール", syn: "sizing guide（サイズガイド）, measurement table（寸法表）" },
  { en: "delivery", pos: "名詞", kana: "デリバリー", ja: "配達", ex: "A: When will my delivery arrive? / B: It says it'll be here by Friday.", exJa: "A: 配達、いつ来るんですか？/ B: 金曜日までには来るって書いてる", cat: "生活", etym: "ラテン語 de-（下へ）+ liberare（自由にする）→ 荷を相手に委ねる・引き渡す。deliver と同根で、手渡しの責任を含む専門用語", syn: "shipment（出荷・配送全般）, dispatch（発送・手配）" },
  { en: "tracking number", pos: "名詞", kana: "トラッキングナンバー", ja: "追跡番号", ex: "A: Did you get the tracking number for your package? / B: Yeah, I'll check it online to see when it arrives.", exJa: "A: 小包の追跡番号をもらった？ / B: うん、ネットで確認して到着日を見るつもり", cat: "生活", etym: "コアイメージ: track（軌跡・痕跡をたどる）+ number。荷物の移動軌跡を番号で追える仕組み", syn: "reference number（参照番号・汎用）, shipment ID（配送ID・システム寄り）" },
  { en: "mailbox", pos: "名詞", kana: "メールボックス", ja: "郵便受け", ex: "A: I haven't checked my mailbox in days. / B: You might be missing important bills then.", exJa: "A: ここ数日郵便受けを見てないんだ。 / B: じゃあ大事な請求書を見落としてるかもね", cat: "生活", etym: "コアイメージ: mail（郵便物）+ box（箱）。郵便物を受け取る箱。mail は中世ラテン語 malia（旅行用バッグ）に由来", syn: "letterbox（英国寄り）, postbox（公共用・英国寄り）" },
  { en: "parcel", pos: "名詞", kana: "パーセル", ja: "小包", ex: "A: Is that parcel for you? / B: Yes, I ordered it from an online store last week.", exJa: "A: その小包あなた宛？ / B: そう、先週ネットショップで注文したんだ", cat: "生活", etym: "ラテン語 particella（小さな部分）に由来。もともと「細かく分けたもの」→「小分けされた荷物」の意", syn: "package（汎用・パッケージ）, shipment（配送物・フォーマル）" },
  { en: "courier", pos: "名詞", kana: "クーリエ", ja: "宅配便", ex: "A: How will the package arrive? / B: By courier—it should be here by tomorrow.", exJa: "A: 荷物はどうやって来る？ / B: 宅配便で、明日までには着くはず", cat: "生活", etym: "フランス語 courrier、ラテン語 currere（走る）に由来。「走って運ぶ人」→「急速配送サービス」へ。current・course と同根", syn: "delivery service（配送サービス・汎用）, messenger service（メッセンジャーサービス・緊急性重視）" },
  { en: "pickup", pos: "名詞", kana: "ピックアップ", ja: "受け取り", ex: "A: When can you do the pickup? / B: I'm free after 5 PM on weekdays.", exJa: "A: いつ受け取りに来られますか？ / B: 平日は午後5時以降なら大丈夫です", cat: "生活", etym: "コアイメージ: pick up（拾い上げる）。何かを取りに行く・受け取りに行く動作。名詞化すると「受け取り」「引き取り」", syn: "collection（集荷・フォーマル）, retrieval（回収・システム寄り）" },
  { en: "drop-off", pos: "名詞", kana: "ドロップオフ", ja: "預け入れ", ex: "A: Where's the nearest drop-off location? / B: There's one at the convenience store next to the station.", exJa: "A: 一番近い預け入れ場所はどこ？ / B: 駅隣のコンビニに一つありますよ", cat: "生活", etym: "コアイメージ: drop off（降ろす・置いていく）。荷物を店舗や施設に置いていく行為。drop-off point で集荷所", syn: "submission（提出・フォーマル）, handover（引き渡し）" },
  { en: "commuter pass", pos: "名詞", kana: "コミューターパス", ja: "定期券", ex: "A: Do you have a commuter pass? / B: Yes, it covers my train and bus rides for three months.", exJa: "A: 定期券を持ってますか？ / B: はい、電車とバスで3ヶ月分です", cat: "生活", etym: "commute はラテン語 commutare（交換する）に由来。「毎日往復する人のための交換可能なパス」", syn: "season ticket（定期券・汎用）, transit pass（公共交通パス）" },
  { en: "one-way ticket", pos: "名詞", kana: "ワンウェイチケット", ja: "片道切符", ex: "A: Should I buy a one-way or round-trip ticket? / B: If you're not sure when you'll return, go with one-way.", exJa: "A: 片道と往復、どっち買う？ / B: 帰りの時間がまだなら片道にしておきなよ", cat: "生活", etym: "コアイメージ: one-way（一方向）。目的地まで片方向のみ。way はラテン語 via（道）に由来", syn: "single ticket（片道・英国寄り）" },
  { en: "round-trip ticket", pos: "名詞", kana: "ラウンドトリップチケット", ja: "往復切符", ex: "A: I got a round-trip ticket because it's cheaper than buying two separate ones. / B: Smart choice—you save about 10%.", exJa: "A: 往復切符にしたほうが安いから往復で買ったよ。 / B: 正解、大体10%割引になるし", cat: "生活", etym: "コアイメージ: round-trip（往復）= round（一周する）+ trip（旅）。出発地に戻ってくる一周の旅", syn: "return ticket（往復・英国寄り）" },
  { en: "seat assignment", pos: "名詞", kana: "シートアサインメント", ja: "座席指定", ex: "A: Does your ticket include seat assignment? / B: No, it's first-come, first-served on the bus.", exJa: "A: そのチケット座席指定は含まれてますか？ / B: いいえ、バスは先着順です", cat: "生活", etym: "コアイメージ: seat（座席）+ assignment（割り当て）。事前に座席が指定される仕組み。assign はラテン語 assignare（割り当てる）", syn: "reserved seat（指定席・汎用）, seat selection（座席選択）" },
  { en: "window seat", pos: "名詞", kana: "ウィンドウシート", ja: "窓側席", ex: "A: I prefer window seats on flights. / B: Me too, but the aisle seat is better for bathroom access.", exJa: "A: 飛行機は窓側派です。 / B: 私もだけど、トイレの時は通路側が便利ですね", cat: "生活", etym: "コアイメージ: window（窓）+ seat（座席）。飛行機や列車で窓に面した座席。window はゲルマン語 wind（風）+ eye（目）が語源", syn: "window side（窓側・説明的）" },
  { en: "aisle seat", pos: "名詞", kana: "アイルシート", ja: "通路側席", ex: "A: Would you like an aisle or window seat? / B: Aisle, please—I need to stretch my legs on long flights.", exJa: "A: 通路側と窓側、どちらにしますか？ / B: 通路側で、長いフライトは足を伸ばしたいので", cat: "生活", etym: "aisle はフランス語 aile（翼）→ラテン語 ala に由来。左右に翼のように広がる通路。中央通路の側の座席", syn: "aisle side（通路側・説明的）" },
  { en: "overhead bin", pos: "名詞", kana: "オーバーヘッドビン", ja: "手荷物棚", ex: "A: Can I fit this suitcase in the overhead bin? / B: It looks too big—you'll need to check it.", exJa: "A: このスーツケース手荷物棚に入りますか？ / B: 大きすぎて見えるので、預け荷物にしたほうが", cat: "生活", etym: "コアイメージ: overhead（頭上の）+ bin（容器・箱）。頭上の荷物棚。overhead はオランダ語 over + head に由来", syn: "overhead compartment（手荷物棚・フォーマル）, luggage rack（荷物棚・汎用）" },
  { en: "carry-on", pos: "名詞", kana: "キャリーオン", ja: "機内持ち込み荷物", ex: "A: How much carry-on baggage is allowed? / B: Usually one personal item and one roller bag.", exJa: "A: 機内持ち込み荷物はいくつまで？ / B: 普通は貴重品かばん１個とキャリーバッグ１個", cat: "生活", etym: "コアイメージ: carry on（持ち込む）。機内に持ち込める小さな荷物。搭乗時に carry（運ぶ）+ on（～に）で持ち込む", syn: "hand baggage（手荷物・英国寄り）, cabin baggage（客室荷物・国際線寄り）" },
  { en: "checked baggage", pos: "名詞", kana: "チェックドバゲージ", ja: "預け荷物", ex: "A: How many bags can I check for free? / B: Two bags are included, and extra bags cost $30 each.", exJa: "A: 無料で預けられる荷物は何個？ / B: ２個まで無料で、それ以上は１個３０ドル", cat: "生活", etym: "コアイメージ: check in（チェックインする）。チェックイン時に預ける荷物。check は「確認・チェック」→「預ける」へ", syn: "checked luggage（預け荷物・汎用）, hold baggage（機体下預け・英国寄り）" },
  { en: "luggage tag", pos: "名詞", kana: "ラゲッジタグ", ja: "手荷物タグ", ex: "A: Did you attach your luggage tag before checking in? / B: Yes, I made sure it has my phone number on it.", exJa: "A: チェックインする前に手荷物タグを付けた？ / B: うん、電話番号を書いておいた", cat: "生活", etym: "コアイメージ: luggage（荷物）に tag（札・ラベル）を付けて識別する。baggage tag とも言う", syn: "baggage label（荷物タグ・より正式）, luggage label（同義）" },
  { en: "hotel lobby", pos: "名詞", kana: "ホテルロビー", ja: "ホテルのロビー", ex: "A: Let's meet in the hotel lobby at 7 PM. / B: Sounds good. I'll be by the elevator.", exJa: "A: ホテルのロビーで夜7時に会おう / B: いいね。エレベーターの近くにいるよ", cat: "生活", etym: "ロビー lobby はイタリア語 loggia（柱廊）に由来。ホテルの玄関ホール全体を指す", syn: "reception area（受付周辺・より広い）, entrance hall（玄関ホール）" },
  { en: "front desk", pos: "名詞", kana: "フロントデスク", ja: "受付", ex: "A: Excuse me, could I call the front desk? / B: Of course. The phone is right there.", exJa: "A: すみません、フロント呼べますか？ / B: もちろん。電話はそこです", cat: "生活", etym: "コアイメージ: front（前）の desk（机）→ ホテル正面の受付カウンター。チェックイン・チェックアウト・問い合わせの中心地", syn: "reception desk（受付デスク・より正式）, check-in counter（チェックインカウンター・より限定的）" },
  { en: "room key", pos: "名詞", kana: "ルームキー", ja: "部屋の鍵", ex: "A: I've lost my room key. What should I do? / B: Go to the front desk and they'll issue a new one.", exJa: "A: 部屋の鍵をなくしちゃった。どうしよう / B: フロントに行けば新しいのをくれるよ", cat: "生活", etym: "コアイメージ: room（部屋）を key（鍵）で開ける。キーカード・カードキーが主流だが room key で統一的に呼ばれる", syn: "key card（キーカード・現代的）, room keycard（同義）" },
  { en: "wake-up call", pos: "名詞", kana: "ウェイクアップコール", ja: "モーニングコール", ex: "A: Can I request a wake-up call for 6 AM tomorrow? / B: Sure, I'll note that in your room file.", exJa: "A: 明日朝6時にモーニングコールしてもらえる？ / B: もちろん。お部屋の記録に入れておきます", cat: "生活", etym: "コアイメージ: wake up（目覚める）+ call（電話）→ 朝指定時刻にホテルが電話で起こしてくれるサービス。昔は自動化前は人間が電話していた", syn: "alarm call（アラームコール・英国寄り）, morning call（モーニングコール・同義）" },
  { en: "housekeeping", pos: "名詞", kana: "ハウスキーピング", ja: "客室清掃", ex: "A: Could housekeeping send someone to clean my room? / B: They'll be there in about 30 minutes.", exJa: "A: ハウスキーピングに部屋を掃除してもらえる？ / B: 30分くらいで来ますよ", cat: "生活", etym: "コアイメージ: house（家）+ keeping（管理する）→ ホテルの部屋を家のように整える。housekeeping staff が清掃・リネン交換を担当", syn: "room cleaning（部屋清掃・より一般的）, maid service（メイドサービス・より狭い）" },
  { en: "room service", pos: "名詞", kana: "ルームサービス", ja: "部屋サービス", ex: "A: I'd like to order room service. / B: You can find the menu in your room or dial extension 2.", exJa: "A: ルームサービスで何か注文したい / B: 部屋のメニューか内線2番で注文できます", cat: "生活", etym: "コアイメージ: room（部屋）に service（サービス）を持ってくる → 食事や飲み物をホテルの部屋に配達するサービス", syn: "in-room dining（部屋での食事・より正式）, room delivery（部屋への配達）" },
  { en: "check-in", pos: "名詞", kana: "チェックイン", ja: "宿泊手続き", ex: "A: What time is check-in? / B: Check-in starts at 3 PM, but we can hold your luggage if you arrive early.", exJa: "A: チェックインは何時ですか？ / B: 3時からですが、早着なら荷物を預かります", cat: "生活", etym: "コアイメージ: check in（チェックインする）→ フロントで身分確認・料金支払い・鍵受け取りをして宿泊を開始する行為", syn: "registration（登録・より正式）, arrival（到着・より広い）" },
  { en: "late checkout", pos: "名詞", kana: "レイトチェックアウト", ja: "遅めの退室", ex: "A: Can I do a late checkout? The flight is at 6 PM. / B: Let me check availability. I think we can do 1 PM.", exJa: "A: 遅めのチェックアウトできる？飛行機6時だから / B: 確認しますね。1時まで大丈夫だと思います", cat: "生活", etym: "コアイメージ: late（遅い）checkout（退室）→ 通常より遅い時間に部屋を出ることができるホテルサービス。追加料金が発生することが多い", syn: "extended checkout（チェックアウト延長・同義）, late departure（遅い出発）" },
  { en: "vacancy", pos: "名詞", kana: "ベイカンシー", ja: "空室", ex: "A: Do you have any vacancy for tonight? / B: Yes, we have several rooms available.", exJa: "A: 今夜空いてる部屋ありますか？ / B: はい、何部屋か用意できます", cat: "生活", etym: "ラテン語 vacans（空の、空いている）→ vacare（空いている）に由来。vacant room を簡潔に vacancy と言う", syn: "available room（利用可能な部屋・より一般的）, opening（空き）" },
  { en: "amenity", pos: "名詞", kana: "アメニティ", ja: "備品", ex: "A: What amenities does the hotel offer? / B: Free Wi-Fi, a fitness center, and a 24-hour business center.", exJa: "A: ホテルの設備は何ですか？ / B: 無料Wi-Fi、ジム、24時間のビジネスセンターです", cat: "生活", etym: "ラテン語 amoenus（快適な）に由来。ホテルが客をもてなすための快適な設備・用品を意味する。amenities は複数形で日常的に使われる", syn: "facility（施設・より広い）, perk（サービス特典・より非公式）" },
  { en: "toiletries", pos: "名詞", kana: "トイレタリーズ", ja: "洗面用品", ex: "A: Does the hotel provide toiletries? / B: Yes, you'll find shampoo, soap, and a toothbrush in the bathroom.", exJa: "A: ホテルに洗面用品ついてますか？ / B: はい、シャンプーと石鹸、歯ブラシがバスルームにあります", cat: "生活", etym: "コアイメージ: toilet（トイレ）に関する products → シャンプー・石鹸・歯ブラシなど洗面所で使う用品。toilet articles とも言う", syn: "personal care items（身体用品・より正式）, bathroom supplies（バス用品）" },
  { en: "prescription", pos: "名詞", kana: "プリスクリプション", ja: "処方箋", ex: "A: I need to fill a prescription while I'm in town. / B: There's a pharmacy on the second floor of the shopping center nearby.", exJa: "A: 町にいる間に処方箋を薬局で出したいんだけど / B: 近くのショッピングセンター2階に薬局あります", cat: "生活", etym: "ラテン語 praescribere（前もって書く）→ prae（前もって）+ scribere（書く）。医者が薬の詳細を前もって書いて指示する", syn: "Rx（医学記号・短縮形）, medication order（薬剤指示・より医学的）" },
  { en: "pharmacy", pos: "名詞", kana: "ファーマシー", ja: "薬局", ex: "A: Where can I find a pharmacy around here? / B: There's one in the mall, or try the hospital pharmacy downtown.", exJa: "A: このあたりに薬局ありますか？ / B: モールにあるか、ダウンタウンの病院薬局がありますよ", cat: "生活", etym: "ギリシャ語 pharmakon（薬）に由来。元々は魔法の薬・毒を意味したが、医学が発展して医療用医薬品を調剤・販売する店を指すようになった", syn: "drugstore（薬局・米国寄り）, chemist（薬局・英国寄り）" },
  { en: "clinic", pos: "名詞", kana: "クリニック", ja: "診療所", ex: "A: I'm feeling sick. Is there a clinic nearby? / B: Yeah, there's an urgent care clinic two blocks from here.", exJa: "A: 気分悪いんだけど近くに診療所ある？ / B: うん、ここから2ブロック先に緊急医療センターがある", cat: "生活", etym: "ギリシャ語 klinike（寝床の医学）→ kline（寝床）。患者を寝かせて診察・治療する場所が clinic。病院（hospital）より小規模で外来中心", syn: "medical center（医療センター・より大規模）, doctor's office（医院・個人診療）" },
  { en: "checkup", pos: "名詞", kana: "チェックアップ", ja: "健康診断", ex: "My doctor recommended a full checkup after I mentioned persistent fatigue.", exJa: "医者が継続的な疲労について触れた後、完全な健康診断を勧めてくれた", cat: "生活", etym: "コアイメージ: check（確認する）+ up（～を通じて）→ 体の状態を隅々まで確認する。medical checkup で医学的な確認を意味する", syn: "physical examination（医学的な詳しい検査）, health screening（健康スクリーニング・予防的）, medical exam（医学的検査・総称）" },
  { en: "symptom log", pos: "名詞", kana: "シンプトムログ", ja: "症状記録", ex: "A: Did you keep that symptom log the doctor asked for? / B: Yes, I noted everything—headaches, nausea, and when they occur.", exJa: "A: 医者に頼まれた症状記録つけてた？ / B: うん、頭痛とか吐き気とか全部いつ起きたか記録した", cat: "生活", etym: "symptom はギリシャ語 symptoma（一緒に起こること）に由来。log は記録簿の意。医療現場で症状の経過を追跡する文書", syn: "health diary（健康日記・より広い記録）, symptom tracker（症状追跡アプリ・デジタル）, medical record（医療記録・公式）" },
  { en: "allergy", pos: "名詞", kana: "アレルジー", ja: "アレルギー", ex: "People with peanut allergies need to read food labels carefully.", exJa: "ピーナッツアレルギーがある人は食品ラベルを注意深く読む必要がある", cat: "生活", etym: "ギリシャ語 allos（他の）+ ergon（作用）→ 通常と異なる反応。1906年にオーストリアの小児科医が造語した医学用語", syn: "intolerance（不耐性・消化器系）, sensitivity（感受性・軽い反応）, hypersensitivity（過敏症・医学的）" },
  { en: "bandage", pos: "名詞", kana: "バンデージ", ja: "包帯", ex: "A: That cut looks bad. / B: I know, but I think a bandage will do for now.", exJa: "A: その傷ひどいね / B: だね。でも今のところ包帯で大丈夫だと思う", cat: "生活", etym: "フランス語 bande（帯）に由来。中世から使われている医療用語で、傷を布で包むという基本的な処置から派生", syn: "dressing（創傷被覆・医療用語）, plaster（絆創膏・小さい傷）, gauze（ガーゼ・素材の名称）" },
  { en: "thermometer", pos: "名詞", kana: "サーモメーター", ja: "体温計", ex: "The thermometer showed a fever of 38.5 degrees Celsius.", exJa: "体温計は摂氏38.5度の熱を示していた", cat: "生活", etym: "ギリシャ語 therme（熱）+ metron（測定）→ 熱を測る道具。17世紀のガリレオが温度計を発明した時代から使われている", syn: "temperature gauge（温度計・広い範囲）, fever strip（熱感知テープ・簡易型）" },
  { en: "insurance card", pos: "名詞", kana: "インシュアランスカード", ja: "保険証", ex: "A: Don't forget your insurance card for your appointment tomorrow. / B: Good reminder—I'll grab it now.", exJa: "A: 明日の診察に保険証忘れずにね / B: いい指摘。今すぐ持ってこよう", cat: "生活", etym: "insurance はラテン語 insurare（～に対して確実にする）。医療保険の身分証明として機能する現代の必須文書", syn: "health insurance document（健康保険書類・正式）, insurance ID（保険ID・簡潔）, coverage card（保障カード・総称）" },
  { en: "copayment", pos: "名詞", kana: "コーペイメント", ja: "自己負担額", ex: "The copayment for a specialist visit is typically higher than for a regular checkup.", exJa: "専門医の診察の自己負担額は通常の検診より高い", cat: "生活", etym: "コアイメージ: co-（共に）+ payment（支払い）→ 患者と保険会社が費用を分担する仕組み。アメリカの医療システムで一般的", syn: "deductible（控除額・保険用語）, out-of-pocket cost（実費・患者が払う額）, patient cost-sharing（患者負担額）" },
  { en: "utility bill", pos: "名詞", kana: "ユーティリティビル", ja: "公共料金請求書", ex: "A: Our utility bill jumped this month. / B: Same here—the air conditioning probably did it.", exJa: "A: 今月の公共料金請求書が跳ね上がった / B: うちもだ。たぶるエアコンのせい", cat: "生活", etym: "utility はラテン語 utilitas（有用性）に由来。電気・ガス・水道などの生活に必須のサービス料金", syn: "monthly statement（月額請求書・電気ガス水道全般）, invoice（請求書・より正式）, service bill（サービス料金）" },
  { en: "rent", pos: "名詞", kana: "レント", ja: "家賃", ex: "A: Is your rent due next week? / B: Yeah, I need to transfer the payment to my landlord.", exJa: "A: 家賃来週までだっけ？ / B: そう。家主に振込まないと", cat: "生活", etym: "ラテン語 rendita（収益）に由来。中世ヨーロッパで土地所有者に定期的に支払う対価として発展した概念", syn: "monthly payment（月額支払い・広い範囲）, lease payment（賃借料金・契約的）, housing payment（住宅支払い）" },
  { en: "lease", pos: "名詞", kana: "リース", ja: "賃貸契約", ex: "Most apartments require a one-year lease, though some landlords offer shorter terms.", exJa: "ほとんどのアパートは1年のリース契約を要求するが、家主によっては短期もある", cat: "生活", etym: "ラテン語 laxare（緩める・解放する）に由来。賃借人に一定期間の使用権を与える法的契約文書", syn: "rental agreement（賃貸契約書・より日常的）, tenancy agreement（テナント契約・英国寄り）, contract（契約・総称）" },
  { en: "landlord", pos: "名詞", kana: "ランドロード", ja: "家主", ex: "A: Should we call the landlord about the leak? / B: Definitely—it's his responsibility.", exJa: "A: 漏水について家主に電話すべき？ / B: 絶対。それは家主の責任だ", cat: "生活", etym: "コアイメージ: land（土地）+ lord（領主）→ 土地の所有者兼統治者。中世からの階級社会の名残が語源に残っている", syn: "property owner（不動産所有者・広い範囲）, lessor（貸し手・法律用語）, landlady（女性の家主）" },
  { en: "tenant", pos: "名詞", kana: "テナント", ja: "入居者", ex: "The tenant reported water damage in the kitchen to the property manager.", exJa: "入居者がキッチンの水害を物件管理者に報告した", cat: "生活", etym: "ラテン語 tenere（保つ・保有する）に由来。一定期間、他人の物件を保有・使用する者を指す法律用語", syn: "renter（借り手・アメリカ英語）, occupant（占有者・より広い）, lessee（借地人・法律用語）" },
  { en: "maintenance", pos: "名詞", kana: "メンテナンス", ja: "修理対応", ex: "A: The toilet's broken. Should I call maintenance? / B: Yes, submit a work order right away.", exJa: "A: トイレ壊れた。修理に電話すべき？ / B: うん、すぐに作業依頼出して", cat: "生活", etym: "ラテン語 manutenere（手で保つ）→ maintain（維持する）に由来。建物・設備を良好な状態に保つための業務", syn: "upkeep（維持管理・予防的）, repairs（修理・問題が起きた時）, servicing（サービス・定期的）" },
  { en: "repair request", pos: "名詞", kana: "リペアリクエスト", ja: "修理依頼", ex: "A: I filed a repair request for the heating system yesterday. / B: Good idea—winter's coming.", exJa: "A: 昨日暖房システムの修理依頼出した / B: いいね。冬が来るし", cat: "生活", etym: "repair はラテン語 reparare（作り直す）に由来。修理対応を正式に要請する住宅管理の標準的な手続き", syn: "maintenance request（修理・維持管理の依頼）, work order（作業指示書・より正式）, trouble ticket（トラブルチケット・IT寄り）" },
  { en: "furniture", pos: "名詞", kana: "ファニチャー", ja: "家具", ex: "A: Are you bringing furniture to your new apartment? / B: Just my bed and desk—the rest I'll buy there.", exJa: "A: 新しいアパートに家具持ってく？ / B: ベッドと机だけ。あとはそこで買う", cat: "生活", etym: "フランス語 fourniture（装備・備品）に由来。部屋を「装備する」ための大型の可動式備品の総称", syn: "furnishings（調度品・より幅広い装飾）, household items（家庭用品・生活用品全般）, fixtures（付属品・固定的）" },
  { en: "appliance", pos: "名詞", kana: "アプライアンス", ja: "家電", ex: "Modern appliances have become more energy-efficient, helping households reduce their electricity bills.", exJa: "現代の家電はより省エネになり、家庭の電気代削減に役立っている", cat: "生活", etym: "ラテン語 applicare（適用する・応用する）に由来。apply と同根で、「実際に応用される道具」という意味から家庭用電化製品を指すようになった", syn: "device（汎用的な装置）, gadget（小型の便利グッズ）, equipment（設備・総称）" },
  { en: "vacuum cleaner", pos: "名詞", kana: "バキュームクリーナー", ja: "掃除機", ex: "A: My vacuum cleaner isn't picking up dirt anymore. / B: You probably need to empty the bag and replace the filter.", exJa: "A: 掃除機がゴミを吸い込まなくなったんだ。/ B: おそらくバッグを空にしてフィルターを交換する必要があるよ", cat: "生活", etym: "vacuum はラテン語 vacuus（空の）に由来。空気を吸い込んで空間を作り出す原理から named。cleaner は clean + -er（道具）", syn: "hoover（英国用語・商標化）, suction cleaner（吸引型清掃機）" },
  { en: "air conditioner", pos: "名詞", kana: "エアコンディショナー", ja: "エアコン", ex: "A: It's too hot. Can you turn on the air conditioner? / B: Sure, I'll set it to 22 degrees.", exJa: "A: 暑いね。エアコンつけてくれない？/ B: もちろん、22度に設定するよ", cat: "生活", etym: "air（空気）+ condition（状態を整える）→ 空気の温度・湿度を調整する装置。condition は ラテン語 condicio（条件・状態）に由来", syn: "AC（略語）, cooling system（冷却システム・総称）, HVAC（暖冷房設備・業務用）" },
  { en: "heater", pos: "名詞", kana: "ヒーター", ja: "暖房", ex: "A: The heater is broken. It's freezing in here! / B: Let me call a repairman to fix it.", exJa: "A: 暖房が壊れてる。凍えちゃう！/ B: 修理人を呼んで直してもらおう", cat: "生活", etym: "heat（熱）+ -er（道具・人）。heat はゲルマン語系で「温かさ」を意味する。対義語は cooler、より正式には heating system", syn: "heating system（暖房システム・総称）, radiator（ラジエーター・欧州式）, furnace（大型暖房炉）" },
  { en: "curtain", pos: "名詞", kana: "カーテン", ja: "カーテン", ex: "A: Can you close the curtains? The sun is too bright. / B: I'll do it right now.", exJa: "A: カーテンを閉めてくれない？日が眩しいよ。/ B: 今すぐやるね", cat: "生活", etym: "ラテン語 curtus（短い）→ 古フランス語 cortine（幕）。劇場の幕や窓を覆う布を指すようになった。curtsy（お辞儀）も同根", syn: "drape（厚手のドレープカーテン）, blind（ブラインド・ルーバー式）, shade（シェード・巻き上げ式）" },
  { en: "closet", pos: "名詞", kana: "クローゼット", ja: "収納", ex: "A: Where should I put my winter clothes? / B: Just hang them in the closet upstairs.", exJa: "A: 冬物をどこに置こう？/ B: 上の階のクローゼットにかけておいて", cat: "生活", etym: "コアイメージ: close（閉じる）→ 何かを close off した小部屋。もともとは「物を仕舞い込む小さな密閉空間」を指した", syn: "wardrobe（衣類専用の収納）, cabinet（キャビネット・食器棚など）, storage（一般的な収納）" },
  { en: "neighborhood", pos: "名詞", kana: "ネイバーフッド", ja: "近所", ex: "A: How's your new neighborhood? / B: It's quiet and friendly. Everyone knows each other.", exJa: "A: 新しい近所はどう？/ B: 静かで友好的だよ。みんなお互いのことを知ってるし", cat: "生活", etym: "コアイメージ: neighbor（隣人）+ -hood（状態・地域）→ 隣同士の人々が住む地域。hood は hood（フード）ではなく古英語 had（状態）が語源", syn: "community（地域社会・人間関係も含む）, vicinity（周辺・より広い範囲）, locality（地域・行政的）" },
  { en: "community center", pos: "名詞", kana: "コミュニティセンター", ja: "地域センター", ex: "A: I'm thinking of joining a yoga class. / B: Great! The community center offers one every Tuesday.", exJa: "A: ヨガクラスに入ろうかと思ってるんだ。/ B: いいね！地域センターが毎週火曜日にやってるよ", cat: "生活", etym: "community はラテン語 communis（共通の）に由来。center は kentron（ギリシア語で中心）。「地域共通の活動の中心地」", syn: "civic center（市民センター・行政的）, recreation center（レクリエーションセンター・娯楽重視）" },
  { en: "membership", pos: "名詞", kana: "メンバーシップ", ja: "会員資格", ex: "A: Do I need membership to use the gym? / B: Yes, it costs about 5,000 yen per month.", exJa: "A: ジムを使うのに会員資格が必要ですか？/ B: はい、月々約5,000円です", cat: "生活", etym: "member（会員）+ -ship（状態・資格）。member はラテン語 membrum（肢体）→「組織の一部を成す人」。-ship は kingdom や friendship と同じ接尾辞", syn: "enrollment（登録・手続き重視）, subscription（購読会員制）, registration（登録・総称）" },
  { en: "subscription plan", pos: "名詞", kana: "サブスクリプションプラン", ja: "定期契約プラン", ex: "A: Which subscription plan should I choose? / B: The annual plan saves you 20% compared to the monthly option.", exJa: "A: どの定期プランを選ぶべき？/ B: 年間プランは月額より20%安いよ", cat: "生活", etym: "subscribe はラテン語 subscribere（下に署名する→契約する）。sub（下）+ scribere（書く）。同根語は scribe, description, manuscript", syn: "service plan（サービスプラン・総称）, membership tier（会員レベル・段階制）, package（パッケージ・セット）" },
  { en: "renewal", pos: "名詞", kana: "リニューアル", ja: "更新", ex: "A: When does your phone contract renew? / B: Next month. I'm hoping to get a new model.", exJa: "A: スマホの契約いつ更新ですか？/ B: 来月です。新機種が欲しいんです", cat: "生活", etym: "renew は re（再び）+ new（新しく）。古フランス語 noveler に由来。「新しくし直す」という意味から、契約や免許などの更新を指すようになった", syn: "extension（延長・より短期的）, reactivation（再開・中断後の再開）, refresh（更新・内容刷新も含む）" },
  { en: "cancellation fee", pos: "名詞", kana: "キャンセレーションフィー", ja: "解約手数料", ex: "A: I want to cancel my contract, but what about the cancellation fee? / B: There's a 10,000 yen penalty if you terminate early.", exJa: "A: 契約を解約したいんですが、解約手数料はいくらですか？/ B: 早期終了だと1万円のペナルティがあります", cat: "生活", etym: "cancel はラテン語 cancellare（格子状に打ち消す）。fee はゲルマン語系で「報酬・手数料」。cancel と cell（格子）は同根", syn: "early termination fee（早期解約料・契約期間内の解除）, penalty fee（ペナルティ料金）" },
  { en: "bank transfer", pos: "名詞", kana: "バンクトランスファー", ja: "銀行振込", ex: "A: How should I pay for this? / B: Please make a bank transfer to the account number I'll send you.", exJa: "A: どうやって払えばいいですか？/ B: 送った口座番号に銀行振込でお願いします", cat: "生活", etym: "bank はイタリア語 banca（机・金融機関）に由来。transfer は trans（越えて）+ ferre（運ぶ）。「お金を別の口座に運ぶ」", syn: "wire transfer（電信送金・特に海外）, direct deposit（自動振込・給与受け取り等）, ACH transfer（自動決済）" },
  { en: "account balance", pos: "名詞", kana: "アカウントバランス", ja: "口座残高", ex: "A: Can you check my account balance at the ATM? / B: Sure, your balance is 150,000 yen.", exJa: "A: ATMで口座残高を確認してくれません？/ B: もちろん、残高は15万円です", cat: "生活", etym: "account はラテン語 computare（数える）に由来。balance は「天秤」から「均衡・差額」へ。帳簿が釣り合う金額を指す", syn: "balance（残額・総称）, available balance（利用可能額・引き出せる額）" },
  { en: "withdrawal slip", pos: "名詞", kana: "ウィズドローアルスリップ", ja: "出金票", ex: "A: Where can I get a withdrawal slip? / B: The forms are at the counter. Fill it out and give it to the clerk.", exJa: "A: 出金票はどこで手に入りますか？/ B: カウンターにあります。記入して窓口の人に出してください", cat: "生活", etym: "withdrawal は withdraw（引き出す）から。with（共に）+ draw（引く）→ 「持ち出す」。slip は「紙片」という意味の古い言葉", syn: "withdrawal form（出金フォーム）, check（小切手・紙ベースの引き出し）" },
  { en: "deposit slip", pos: "名詞", kana: "デポジットスリップ", ja: "入金票", ex: "Please fill out the deposit slip with your account number and the amount you want to deposit.", exJa: "入金票にあなたの口座番号と入金額を記入してください。", cat: "生活", etym: "コアイメージ: deposit（預ける）+ slip（紙片）→ 銀行に現金を預けるときに記入する小さな用紙。deposit は de-（下へ）+ positum（置く）が語源で「下に置く＝預ける」", syn: "payment voucher（支払い伝票・一般的）, lodgment form（入金フォーム・英国寄り）" },
  { en: "passbook", pos: "名詞", kana: "パスブック", ja: "通帳", ex: "The bank has stopped issuing passbooks, and customers must check their balance online instead.", exJa: "銀行は通帳の発行を中止し、顧客はオンラインで残高を確認する必要があります。", cat: "生活", etym: "コアイメージ: pass（通す）+ book（本）→ 銀行を通して金銭のやり取りを記録した小冊子。かつては出入金のたびに銀行に提示して更新した", syn: "bank book（銀行通帳・やや古い）, savings account record（貯蓄口座記録）" },
  { en: "credit limit", pos: "名詞", kana: "クレジットリミット", ja: "利用限度額", ex: "Your credit limit has been increased from $5,000 to $7,500 based on your payment history.", exJa: "支払い履歴に基づいて、あなたの利用限度額は5,000ドルから7,500ドルに引き上げられました。", cat: "生活", etym: "コアイメージ: credit（信用・借金）+ limit（限界）→ カード会社が個人の信用度に基づいて決める、使える上限額。credit は credere（信じる）が語源", syn: "credit ceiling（信用枠の上限）, spending cap（支出上限）" },
  { en: "installment", pos: "名詞", kana: "インストールメント", ja: "分割払い", ex: "You can purchase this laptop in 12 monthly installments with zero interest.", exJa: "このノートパソコンは12ヶ月分割払い、金利ゼロで購入できます。", cat: "生活", etym: "ラテン語 installare（据え付ける）が語源。複数回に分けて「据え付ける＝支払う」意味から。install（インストール）と同根", syn: "payment plan（支払い計画）, hire purchase（分割購入・英国寄り）" },
  { en: "contactless payment", pos: "名詞", kana: "コンタクトレスペイメント", ja: "タッチ決済", ex: "Most convenience stores in Japan now accept contactless payment via smartphone.", exJa: "日本のほとんどのコンビニはスマートフォンでのタッチ決済を受け付けています。", cat: "生活", etym: "コアイメージ: contactless（接触なし）→ カードやスマートフォンをリーダーに「タッチ」するだけで決済完了。近年のNFC技術による革新的な支払い方法", syn: "NFC payment（近距離無線通信決済・技術用語）, tap payment（タップ決済・シンプル）" },
  { en: "notification", pos: "名詞", kana: "ノーティフィケーション", ja: "通知メッセージ", ex: "You will receive a notification whenever your credit card transaction is processed.", exJa: "クレジットカード取引が処理されるたびに通知を受け取ります。", cat: "生活", etym: "ラテン語 notificāre（知らせる）← notus（知られた）+ facere（する）→「知られた状態にする＝通知する」。notify と同根", syn: "alert（警告通知・緊急性を伴う）, message（メッセージ・一般的）" },
  { en: "settings", pos: "名詞", kana: "セッティングス", ja: "設定", ex: "Go to Settings to change your password and enable two-factor authentication.", exJa: "設定に移動してパスワードを変更し、二要素認証を有効にしてください。", cat: "生活", etym: "コアイメージ: set（セット・設定する）+ ings（名詞化）→ アプリやシステムの細かい調整・カスタマイズを行う場所。もともと「置く」という意味の set から発展", syn: "configuration（設定値・技術的）, preferences（好み設定・ユーザー志向）" },
  { en: "language option", pos: "名詞", kana: "ランゲージオプション", ja: "言語設定", ex: "The language option is located in the menu; simply select your preferred language.", exJa: "言語設定はメニューにあり、希望する言語を選択するだけです。", cat: "生活", etym: "コアイメージ: language（言語）+ option（選択肢）→ 複数の言語から選べるメニュー。option は optāre（選ぶ）が語源", syn: "language preference（言語選択・ユーザー志向）, locale setting（ロケール設定・技術用語）" },
  { en: "update notice", pos: "名詞", kana: "アップデートノーティス", ja: "更新案内", ex: "An update notice appeared on my phone asking me to upgrade to the latest version.", exJa: "最新バージョンへのアップグレードを求める更新案内が携帯に表示されました。", cat: "生活", etym: "コアイメージ: update（最新情報に更新）+ notice（告知）→ アプリやシステムの新バージョン提供を事前に知らせる通知。update は up-（上へ）+ date（日付）", syn: "release announcement（リリース告知）, patch notification（パッチ通知・技術的）" },
  { en: "user guide", pos: "名詞", kana: "ユーザーガイド", ja: "利用案内", ex: "Before opening an account, please read the user guide to understand the fees and terms.", exJa: "口座開設前に、利用案内を読んで手数料と条件を理解してください。", cat: "生活", etym: "コアイメージ: user（ユーザー）+ guide（案内・ガイド）→ サービスやアプリの使い方を説明する文書。guide は 中世ラテン語 guida が語源", syn: "manual（マニュアル・詳細な説明書）, tutorial（チュートリアル・段階的指導）" },
  { en: "help desk", pos: "名詞", kana: "ヘルプデスク", ja: "問い合わせ窓口", ex: "If you have any questions about your account, please contact our help desk.", exJa: "アカウントについてご質問がある場合は、問い合わせ窓口までお問い合わせください。", cat: "生活", etym: "コアイメージ: help（助け）+ desk（机・カウンター）→ ユーザーが困ったときに相談できるサポート部門。かつては実際に机があった物理的な場所から", syn: "customer support（顧客サポート・一般的）, service center（サービスセンター）" },
  { en: "feedback form", pos: "名詞", kana: "フィードバックフォーム", ja: "意見フォーム", ex: "Please complete the feedback form to help us improve our service.", exJa: "サービス向上のため、意見フォームにご記入ください。", cat: "生活", etym: "コアイメージ: feedback（フィードバック・評価）+ form（形式・フォーム）→ ユーザーの意見や不満を集めるための定型フォーム。feedback は feed-（与える）+ back（返す）", syn: "survey form（調査フォーム）, comment box（意見箱・より広い意味）" },
  { en: "satisfaction survey", pos: "名詞", kana: "サティスファクションサーベイ", ja: "満足度調査", ex: "After closing your account, you may receive a satisfaction survey asking for your feedback.", exJa: "口座閉鎖後、フィードバックを求める満足度調査が送られることがあります。", cat: "生活", etym: "コアイメージ: satisfaction（満足）+ survey（調査）→ ユーザーの満足度を数値化して把握するアンケート。survey はラテン語 supervisus（見守る）が語源", syn: "customer satisfaction questionnaire（顧客満足度アンケート・正式）, NPS survey（顧客推奨度調査・測定方法の一種）" },
  { en: "onboarding", pos: "名詞", kana: "オンボーディング", ja: "導入手続き", ex: "The onboarding process includes identity verification and setting up your initial preferences.", exJa: "導入手続きには本人確認と初期設定の選択が含まれます。", cat: "生活", etym: "コアイメージ: on-（乗る）+ boarding（乗船・搭乗）→ 新しいユーザーやスタッフを「乗船させる」ように段階的に導入・統合していくプロセス", syn: "orientation（オリエンテーション・研修や説明）, induction program（導入プログラム・正式用語）" },
  { en: "offboarding", pos: "名詞", kana: "オフボーディング", ja: "退職手続き", ex: "The offboarding checklist ensures all accounts and data are properly closed when an employee leaves.", exJa: "退職手続きチェックリストは従業員退職時にすべてのアカウントとデータが適切に閉鎖されることを確認します。", cat: "生活", etym: "コアイメージ: off-（降りる）+ boarding（乗船）→ onboarding の反対語。ユーザーやスタッフを「乗船から降ろす」ように段階的に終了させるプロセス", syn: "exit process（退出プロセス・広い意味）, employee separation（従業員離職手続き・正式）" },
];
